async function promoteBelief(snapshotId,target){try{const data=await api('/api/belief-promote',{method:'POST',body:JSON.stringify({snapshotId,target})});if(target==='truth'){toast(data.existing?'Truth reinforced — already in Truths.':'Truth promoted to Review. It will appear publicly after approval.');mode='truths';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-truths')?.classList.add('active');await loadGraphStatus();await renderTruths();return}if(data.claimId){toast(data.existing?'Existing claim opened in Study.':'Claim promoted to Review. It will appear publicly after approval.');mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await loadGraphStatus();await loadClaims(false);await selectClaim(data.claimId);return}toast('Belief promoted')}catch(e){toast(e.message||(target==='truth'?'Truth promotion failed.':'Claim promotion failed.'))}}
function renderArena(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML=`<div class="section-head"><h2>Claims</h2>${graphBox()}</div><div class="grid">${claims.map(c=>card(c,true)).join('')||'<div class="panel"><div class="empty-state"><p>No claims match this view.</p><p class="small">Claims are public, testable statements with evidence and pressure attached. Use the <b>Submit</b> tab to add one, or adjust the verdict filter above.</p><div class="actions" style="margin-top:8px"><button class="primary" onclick="setMode(\'submit\')">Submit Claim</button><button onclick="document.getElementById(\'filter\').value=\'all\';loadClaims(true)">Show all</button></div></div></div>'}</div>`}
function card(c,actions=false){const votes=`<span title="Believe">▲ ${esc(c.beliefYes||0)}</span><span title="Reject">▼ ${esc(c.beliefNo||0)}</span><span title="Unsure">~ ${esc(c.uncertainty||0)}</span>${c.contradictions?`<span class="claim-pressure-chip" title="Pressure points">⊘ ${esc(c.contradictions)} pressure</span>`:''}`;const metaParts=[c.type,c.handle?'by '+c.handle:''].filter(Boolean).map(esc).join(' · ');return`<article class="card claim-card"><div class="claim-card-head"><span class="badge ${cls(c.status)}">${esc(c.status||'unknown')}</span>${c.category?`<span class="claim-cat">${esc(c.category)}</span>`:''}</div><h3 class="claim-title">${esc(cleanClaimLabel(c.claim))}</h3>${reviewStatusBadge(c)}${metaParts?`<p class="claim-meta small">${metaParts}</p>`:''}<div class="meters">${meter('Evidence',c.evidenceScore)}${meter('Test',c.testability)}${meter('Survive',c.survivability)}</div><div class="claim-votes">${votes}</div>${actions?`<div class="actions"><button class="primary claim-study-btn" onclick="selectClaim('${esc(c.id)}')">Study Claim →</button></div>`:''}</article>`}
const CLAIM_TYPE_HINTS={'Physical/Testable':'Factual statements about the physical world — scientific, empirical, or statistical. Best suited for this system.','Historical':'Claims about past events. Specify dates, actors, or documented outcomes where possible.','Religious/Belief':'Matters of faith or personal conviction. Difficult to falsify — evidence scores will reflect that.','Conspiracy':'Allegations of coordinated deception. Requires specific claims about who, what, and when — not just suspicion.','Product Claim':'Marketing or performance assertions about a specific product or service.','Medical/High Risk':'Health-related claims. Will be flagged for high scrutiny. Be specific and cite sources if you have them.'};
const CAT_CHIPS=['Medicine','Science','Politics','History','Religion','Economics','Law','Technology'];
function updateClaimTypeHint(){const t=document.getElementById('cType')?.value||'Physical/Testable';const el=document.getElementById('cTypeHint');if(el)el.textContent=CLAIM_TYPE_HINTS[t]||'';}
function setCatChip(cat){const el=document.getElementById('cCategory');if(el)el.value=cat;document.querySelectorAll('.cat-chip').forEach(b=>b.classList.toggle('cat-chip-active',b.dataset.cat===cat));}
function renderSubmit(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';if(!_bs.step)_bs.step=1;const html=_bs.step===2?renderBuilderStep2():_bs.step===3?renderBuilderStep3():renderBuilderStep1();document.getElementById('main').innerHTML=html;}
function renderBuilderStep1(){return`<div class="claim-builder"><div class="builder-steps"><span class="builder-step builder-step-active">1 · Raw Thought</span><span class="builder-step">2 · Make It Testable</span><span class="builder-step">3 · Final Claim</span></div><h2>Claim Builder</h2><p class="small submit-trust-note">Scores reflect submitted evidence — not an automatic verdict.</p><p class="small">Write the thought, belief, suspicion, rant, or pattern exactly as it is. HumanX will help sharpen it before Review.</p><div class="hx-form"><label class="small hx-form-field-hint">Your raw thought</label><textarea id="bRaw" rows="3" placeholder="e.g. 'The media always lies about vaccines'" oninput="builderLiveFlags()">${esc(_bs.raw)}</textarea><label class="small hx-form-field-hint">Why do you think this?</label><textarea id="bWhy" rows="2" placeholder="e.g. 'I saw studies contradicting each other'">${esc(_bs.why)}</textarea><label class="small hx-form-field-hint">Where does this apply? (time period, geography, group)</label><input id="bScope" value="${esc(_bs.scope)}" placeholder="e.g. 'UK 2010–2020' or 'US adults aged 18–35'"><label class="small hx-form-field-hint">What would change your mind?</label><input id="bFalsifier" value="${esc(_bs.falsifier)}" placeholder="e.g. 'A meta-analysis showing no drop'"><div id="bFlags" class="builder-flags-live"></div><div class="actions"><button class="primary" onclick="builderNext(1)">Make it testable →</button></div><p class="small review-first-note">Nothing is sent until Step 3.</p></div></div>`;}
function renderBuilderStep2(){const route=claimBuilderRoute(_bs.flags);const routeNote=route==='truth'?'<p class="builder-route builder-route-truth"><span class="badge b-yellow">looks like a Truth</span> This reads more like a belief, value, or widely-repeated assertion. You can sharpen it into a testable claim below — or save the original assertion as a Truth for Review now.</p><div class="builder-route-actions"><button class="primary" onclick="submitBuilderTruth()">Save as Truth for Review</button></div>':'<p class="builder-route builder-route-claim"><span class="badge b-green">looks testable</span> This has the shape of a falsifiable claim. Sharpen the wording and continue.</p>';return`<div class="claim-builder"><div class="builder-steps"><span class="builder-step">1 · Raw Thought</span><span class="builder-step builder-step-active">2 · Make It Testable</span><span class="builder-step">3 · Final Claim</span></div><h2>Make It Testable</h2><div class="builder-original"><p class="small builder-original-label">Original text</p><blockquote class="builder-original-text">${esc(_bs.raw)}</blockquote></div>${renderBuilderFlags(_bs.flags)}${routeNote}<div class="hx-form"><label class="small hx-form-field-hint">Draft claim <span class="small">(edit freely)</span></label><textarea id="bDraft" rows="2" placeholder="One precise, testable statement">${esc(_bs.draft)}</textarea><label class="small hx-form-field-hint">Scope / context</label><input id="bScope2" value="${esc(_bs.scope)}" placeholder="Time period, geography, or group"><label class="small hx-form-field-hint">Falsifier / what would change your mind</label><input id="bFalsifier2" value="${esc(_bs.falsifier)}" placeholder="What evidence would prove this wrong?"><label class="small hx-form-field-hint">Category</label><div class="cat-chips">${CAT_CHIPS.map(c=>`<button type="button" class="cat-chip${_bs.category===c?' cat-chip-active':''}" data-cat="${c}" onclick="builderSetCat('${c}')">${c}</button>`).join('')}</div><input id="bCategory" value="${esc(_bs.category)}" placeholder="Or type a category"><label class="small hx-form-field-hint">Claim type</label><select id="bType" onchange="builderSetType(this.value)">${['Physical/Testable','Historical','Religious/Belief','Conspiracy','Product Claim','Medical/High Risk'].map(t=>`<option${_bs.type===t?' selected':''}>${t}</option>`).join('')}</select><p class="small hx-form-field-hint">${esc(CLAIM_TYPE_HINTS[_bs.type]||'')}</p><div class="actions"><button onclick="builderBack()">← Back</button><button class="primary" onclick="builderNext(2)">Continue to final claim →</button></div><p class="small review-first-note">Not submitted yet.</p></div></div>`;}
function renderBuilderStep3(){const route=claimBuilderRoute(_bs.flags);const isTruth=route==='truth';const decisionBadge=isTruth?'<span class="badge b-yellow">Truth route</span> <span class="badge b-blue">Claim route available</span>':'<span class="badge b-yellow">Submit as Claim for Review</span>';const decisionNote=isTruth?'<p class="small builder-truth-note">Truth route records the original assertion for Review. It does not verify it as fact. You can also submit the cleaned claim instead.</p>':'<p class="small review-first-note">Enters admin Review before going public. Not visible until approved.</p>';const actionBtns=isTruth?'<button onclick="builderBack()">← Back</button><button class="primary" onclick="submitBuilderTruth()">Save as Truth for Review</button><button onclick="submitBuilderClaim()">Submit Claim for Review</button>':'<button onclick="builderBack()">← Back</button><button class="primary" onclick="submitBuilderClaim()">Submit Claim for Review</button>';return`<div class="claim-builder"><div class="builder-steps"><span class="builder-step">1 · Raw Thought</span><span class="builder-step">2 · Make It Testable</span><span class="builder-step builder-step-active">3 · Final Claim</span></div><h2>Final Claim</h2><div class="builder-summary"><div class="builder-summary-row"><span class="builder-summary-label">CLAIM</span><span class="builder-summary-val">${esc(_bs.draft)}</span></div><div class="builder-summary-row"><span class="builder-summary-label">ORIGINAL</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.raw)}</span></div><div class="builder-summary-row"><span class="builder-summary-label">WHY</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.why||'—')}</span></div><div class="builder-summary-row"><span class="builder-summary-label">SCOPE</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.scope||'—')}</span></div><div class="builder-summary-row"><span class="builder-summary-label">FALSIFIER</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.falsifier||'—')}</span></div><div class="builder-summary-row"><span class="builder-summary-label">FLAGS</span><span class="builder-summary-val">${renderBuilderFlags(_bs.flags)||'<span class=\\"small\\">none</span>'}</span></div><div class="builder-summary-row"><span class="builder-summary-label">DECISION</span><span class="builder-summary-val">${decisionBadge}</span></div></div>${decisionNote}<div class="actions">${actionBtns}</div></div>`;}
function claimBuilderFlags(text,scope,falsifier){const flags=[];const t=String(text||'').trim();if(!t||t.length<5)return flags;const lo=t.toLowerCase();if(t.length<20)flags.push({code:'too_short',msg:'Very short — add a specific quantity, date, or outcome.',route:null});if(/^(i think|i believe|i feel|in my opinion|personally)/i.test(lo))flags.push({code:'personal_belief',msg:'Personal framing — reframe as an observable, falsifiable statement.',route:'truth'});if(/^(people are|everyone is|nobody is|all [a-z]+ are)/i.test(lo)&&t.length<60)flags.push({code:'too_broad',msg:'Broad scope — narrow to a specific group, time, or place.',route:null});if(/\b(should|must|ought|need to)\b/i.test(lo)&&!/\b(study|evidence|data|show|prove|found)\b/i.test(lo))flags.push({code:'normative_value',msg:'Normative framing — says what should be rather than what is.',route:'truth'});if(/\b(always|never|all|none|every one|no one)\b/i.test(lo)&&t.length<80)flags.push({code:'too_vague',msg:'Absolute language — hard to test. Add a time range or specific context.',route:null});if(/\b(evil|corrupt|immoral|disgusting|terrible)\b/i.test(lo))flags.push({code:'emotional_rant',msg:'Evaluative language — state the observable act or outcome instead.',route:'truth'});if(/\b(they|the government|the media|big pharma|the elite)\b.*\b(hiding|control|want|plan|secret)\b/i.test(lo))flags.push({code:'conspiracy',msg:'Hidden-actor framing — name the specific actor, act, and evidence.',route:'claim'});if(/\b(will|going to|predict|forecast|by 20\d\d)\b/i.test(lo))flags.push({code:'prediction',msg:'Prediction — future claims score low until evidence arrives.',route:'claim'});if(/\bcauses?\b/i.test(lo)&&!/\b(study|evidence|found|shows|documented|paper)\b/i.test(lo))flags.push({code:'causal',msg:'Causal claim — link to a study or documented mechanism.',route:'claim'});if(falsifier&&String(falsifier).trim().length>5)flags.push({code:'testable_enough',msg:'Falsifier provided — good signal this is testable.',route:'claim'});else flags.push({code:'no_falsifier',msg:'No falsifier yet — what evidence would change your mind?',route:null});return flags;}
function claimBuilderRoute(flags){const truth=(flags||[]).filter(f=>f.route==='truth').length;const claim=(flags||[]).filter(f=>f.route==='claim').length;return(truth>claim&&truth>0)?'truth':'claim';}
function claimBuilderDraft(raw,scope){let t=String(raw||'').trim().replace(/\s+/g,' ');t=t.replace(/^(i think[,]?\s*|i believe[,]?\s*|i feel[,]?\s*|in my opinion[,]?\s*|personally[,]?\s*)/i,'');t=t.charAt(0).toUpperCase()+t.slice(1);if(!t.match(/[.!?]$/))t=t+'.';if(scope&&scope.trim()&&!t.toLowerCase().includes(scope.trim().toLowerCase()))t=t.replace(/[.!?]$/,' — '+scope.trim()+'.');return t.trim();}
function renderBuilderFlags(flags){if(!flags||!flags.length)return'';const clr={too_short:'b-yellow',personal_belief:'b-yellow',too_broad:'b-yellow',normative_value:'b-yellow',too_vague:'b-yellow',emotional_rant:'b-red',conspiracy:'b-blue',prediction:'b-blue',causal:'b-blue',testable_enough:'b-green',no_falsifier:'b-yellow'};return`<div class="builder-flags">${flags.map(f=>`<span class="badge builder-flag ${clr[f.code]||'b-yellow'}">${esc(f.msg)}</span>`).join('')}</div>`;}
function builderLiveFlags(){const raw=(document.getElementById('bRaw')?.value||'').trim();const scope=document.getElementById('bScope')?.value||'';const falsifier=document.getElementById('bFalsifier')?.value||'';const flags=claimBuilderFlags(raw,scope,falsifier);const el=document.getElementById('bFlags');if(el)el.innerHTML=flags.length?renderBuilderFlags(flags):'';}
function builderSetCat(c){_bs.category=c;const el=document.getElementById('bCategory');if(el)el.value=c;document.querySelectorAll('.cat-chip').forEach(b=>b.classList.toggle('cat-chip-active',b.dataset.cat===c));}
function builderSetType(v){_bs.type=v;}
function builderNext(step){if(step===1){const raw=(document.getElementById('bRaw')?.value||'').trim();if(raw.length<5){toast('Add your raw thought before continuing.');return;}_bs.raw=raw;_bs.why=document.getElementById('bWhy')?.value||'';_bs.scope=document.getElementById('bScope')?.value||'';_bs.falsifier=document.getElementById('bFalsifier')?.value||'';_bs.flags=claimBuilderFlags(_bs.raw,_bs.scope,_bs.falsifier);if(!_bs.draft)_bs.draft=claimBuilderDraft(_bs.raw,_bs.scope);_bs.step=2;renderSubmit();}else if(step===2){const draft=(document.getElementById('bDraft')?.value||'').trim();if(draft.length<5){toast('Write a draft claim before continuing.');return;}_bs.draft=draft;_bs.scope=document.getElementById('bScope2')?.value||_bs.scope;_bs.falsifier=document.getElementById('bFalsifier2')?.value||_bs.falsifier;_bs.category=document.getElementById('bCategory')?.value||_bs.category;_bs.type=document.getElementById('bType')?.value||_bs.type;_bs.flags=claimBuilderFlags(_bs.raw,_bs.scope,_bs.falsifier);_bs.step=3;renderSubmit();}}
function builderBack(){if(_bs.step>1){_bs.step--;renderSubmit();}}
function builderPayload(){const route=claimBuilderRoute(_bs.flags);return{route,rawText:_bs.raw||'',why:_bs.why||'',scope:_bs.scope||'',falsifier:_bs.falsifier||'',draftClaim:_bs.draft||'',finalClaim:_bs.draft||'',category:_bs.category||'',claimType:_bs.type||'',systemFlags:(_bs.flags||[]).map(f=>f.code||f)};}
async function submitBuilderClaim(){if(!_bs.draft||_bs.draft.trim().length<5){toast('Go back to Step 2 and write a draft claim first.');return;}const flagSummary=_bs.flags.filter(f=>f.code!=='testable_enough'&&f.code!=='no_falsifier').map(f=>f.code).join(', ');const context=['Claim Builder context:','Original user text: '+_bs.raw,_bs.why?'Why user thinks this: '+_bs.why:'',_bs.scope?'Scope: '+_bs.scope:'',_bs.falsifier?'Pressure/falsifier: '+_bs.falsifier:'',flagSummary?'System flags: '+flagSummary:''].filter(Boolean).join('\n');const body={claim:_bs.draft.trim(),category:_bs.category||'general',type:_bs.type||'Physical/Testable',initialEvidence:context,claim_builder:builderPayload()};try{const data=await api('/api/claims',{method:'POST',body:JSON.stringify(body)});selected=data.claim;_bs={step:1,raw:'',why:'',scope:'',falsifier:'',draft:'',category:'',type:'Physical/Testable',flags:[]};await loadGraphStatus();await loadClaims(false);if(data.existing){toast('This claim already exists.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-blue">already exists</span><h2>Claim already exists</h2><p class="small">A claim with the same meaning is already in the system.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study existing claim</button><button onclick="setMode('submit')">Build another claim</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`;}else{toast('Claim submitted for Review. It will appear publicly after approval.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-yellow">in review</span><h2>Claim submitted for Review</h2><p class="small">Your claim is now in the moderation queue and is not yet public. It will appear publicly after an admin approves it.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study this claim</button><button onclick="setMode('submit')">Build another claim</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`;}}catch(e){const _em=e.message||'';toast(_em==='RATE_LIMITED'?'Too many submissions. Try again in about an hour.':_em==='CLAIM_TOO_SHORT'?'Claim is too short. Add a little more detail before submitting.':_em||'Claim submission failed.');}}
async function submitBuilderTruth(){const statement=(_bs.raw||'').trim();if(!statement||statement.length<5){toast('Go back to Step 1 and enter your original thought first.');return;}const route=claimBuilderRoute(_bs.flags);const body={statement,category:_bs.category||'general',origin:'Claim Builder raw thought',truthType:route==='truth'?'personal-belief':'common',confidenceLabel:'claimed',claim_builder:builderPayload()};try{await api('/api/truths',{method:'POST',body:JSON.stringify(body)});_bs={step:1,raw:'',why:'',scope:'',falsifier:'',draft:'',category:'',type:'Physical/Testable',flags:[]};await loadGraphStatus();await renderTruths();toast('Saved as Truth for Review. It will appear publicly after approval.');}catch(e){const _em=e.message||'';toast(_em==='TRUTH_TOO_SHORT'?'Truth statement is too short. Add a little more detail before submitting.':_em==='RATE_LIMITED'?'Too many submissions. Try again in about an hour.':_em||'Truth submission failed.');}}
function groupEvidenceByCllaim(items){const groups=new Map();for(const e of items){const key=e.claimId||e.claim_id||null;if(!groups.has(key))groups.set(key,{claimId:key,claim:e.claim||null,items:[]});groups.get(key).items.push(e);}return[...groups.values()].sort((a,b)=>{if(!a.claimId&&b.claimId)return 1;if(a.claimId&&!b.claimId)return -1;return(a.claim||'').localeCompare(b.claim||'');});}
function vaultGroupsHtml(items){if(!items.length)return'';const groups=groupEvidenceByCllaim(items);return groups.map(g=>{const sup=g.items.filter(e=>(e.stance||'support')==='support').length;const prs=g.items.filter(e=>{const s=e.stance||'support';return s==='pressure'||s==='attack';}).length;const counts=[sup>0?`${sup} support`:'',prs>0?`${prs} pressure`:''].filter(Boolean).join(' · ');const title=g.claim?cleanClaimLabel(g.claim):'Unlinked evidence';const isUnlinked=!g.claimId;return`<div class="vault-group${isUnlinked?' vault-group-unlinked':''}"><div class="vault-group-head"><span class="vault-group-title">${esc(title)}</span><div class="vault-group-meta"><span class="badge b-blue">${g.items.length} item${g.items.length===1?'':'s'}</span>${counts?`<span class="vault-group-counts">${esc(counts)}</span>`:''} ${g.claimId?`<button class="btn-link-small" onclick="studyFromVault('${esc(g.claimId)}')">Study claim ↗</button>`:''}</div></div><div class="vault-group-grid">${g.items.map(evidenceCard).join('')}</div></div>`;}).join('');}
async function renderVault(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Evidence…</h2></div>';try{await loadEvidenceVault();document.getElementById('casefile').innerHTML=helperText();const count=evidenceVault.length;document.getElementById('main').innerHTML=`<div id="attach-modal" class="attach-modal" style="display:none"></div><div class="vault-header"><div class="vault-header-top"><h2>Evidence Vault</h2><span class="badge b-blue">${count} item${count===1?'':'s'}</span></div><p class="small">Reusable sources, documents, data, and records. Each item can be attached to multiple claims as support or as a pressure attack. Evidence records reflect what has been submitted — not an automatic verdict on the claim.</p>${graphBox()}</div><div class="vault-groups">${vaultGroupsHtml(evidenceVault)||'<div class="empty-state"><p>No evidence records yet.</p><p class="small">Open a claim from the <b>Claims</b> tab, enter Study mode, and use the side panel to add a source or pressure attack. Items saved there appear here and can be reused across multiple claims.</p><div class="actions" style="margin-top:8px"><button class="primary" onclick="setMode(\'arena\')">Browse Claims</button></div></div>'}</div>`}catch(e){renderError(e)}}
function evidenceCard(e){const a=parseAnalysis(e.body);const stance=e.linked_stance||e.stance||'support';const isPressure=stance==='pressure'||stance==='attack';const stanceClr=isPressure?'b-red':stance==='support'?'b-green':'b-yellow';const stanceMod=isPressure?'evidence-card-pressure':stance==='support'?'evidence-card-support':'evidence-card-neutral';const quality=e.quality||'unknown';const qualClr=quality==='repeatable'||quality==='documented'||quality==='media'?'b-blue':quality==='vibes'?'':'b-yellow';const mediaType=e.media_type||e.mediaType||'text';const reliability=e.reliability_score||e.reliabilityScore||null;const date=e.updated_at||e.updatedAt||e.created_at||e.createdAt||null;const dateStr=date?new Date(date).toLocaleDateString():null;const reuse=e.reuse_count||e.reuseCount||null;const claimBlock=e.claim?`<div class="vault-card-claim"><span class="pill">linked claim</span><span class="small">${esc(cleanClaimLabel(e.claim))}</span><span class="badge ${cls(e.claimStatus)}">${esc(e.claimStatus||'unknown')}</span></div>`:'';return`<article class="card evidence-card ${stanceMod}"><div class="vault-card-head"><b class="vault-card-title">${esc(e.title)}</b><div class="vault-card-badges"><span class="badge ${stanceClr}">${esc(stance)}</span><span class="badge ${qualClr}">${a?'analysis':esc(quality)}</span><span class="badge">${esc(mediaType)}</span>${reliability?`<span class="pill">reliability ${esc(reliability)}</span>`:''} ${reuse&&reuse>1?`<span class="pill">↻ reused ${esc(reuse)}×</span>`:''}</div></div>${a?analysisSummary(a):evidenceBodyHtml(e.body||e.note||'',240)}${sourceLink(e.sourceUrl||e.source_url)}${claimBlock}${dateStr?`<p class="small vault-card-date">Updated ${esc(dateStr)}</p>`:''}<div class="actions">${(e.claimId||e.claim_id)?`<button onclick="studyFromVault('${esc(e.claimId||e.claim_id)}')" title="Open the linked claim in Study mode">Study Linked Claim</button>`:''}<button class="primary" onclick="attachEvidencePrompt('${esc(e.id)}')" title="Attach this item to a different claim as support or pressure">Attach to Claim</button></div></article>`}
function analysisSummary(a){return`<div class="analysis-card"><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><div class="meters">${meter('Evidence',a.evidence_score||a.evidenceScore||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||a.plainLanguageSummary||'Legacy analysis result stored in evidence. New results should be saved in Analysis.')}</p></div>`}
async function renderTruths(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Truths…</h2></div>';try{await loadTruths();const _isAdm=!!adminToken();const _artCnt=(truths||[]).filter(isTruthArtifact).length;const _brdCnt=(truths||[]).filter(t=>isTruthBorderlineArtefact(t)&&!isTruthArtifact(t)).length;const _perCnt=(truths||[]).filter(isTruthPersonalBelief).length;document.getElementById('casefile').innerHTML=helperText();document.getElementById('main').innerHTML=`<div class="section-head"><h2>Truths</h2><span class="badge b-yellow">widely asserted · not auto-verified</span>${graphBox()}</div><p class="small" style="margin:0 0 10px">Statements that circulate as fact — slogans, doctrines, inherited certainties, repeated beliefs. <b>Public means visible, not proven.</b> Recording a truth here does not verify it. Use <b>Pressure-test as Claim</b> to submit one for evidence-based review.</p><details class="truth-add-details"><summary class="truth-add-summary">Add a public Truth</summary><div class="panel compact-form hx-form"><h3 class="hx-form-head">Add a Truth</h3><input id="truthStatement" placeholder="Repeated statement or widely-asserted belief"><input id="truthCategory" placeholder="Category (e.g. Health, Religion, Politics)"><input id="truthOrigin" placeholder="Origin (e.g. family, media, scripture, science)"><p class="small hx-form-field-hint">Truth type</p><select id="truthType"><option value="common">Common truth</option><option value="religious">Religious truth</option><option value="political">Political truth</option><option value="scientific">Scientific consensus</option><option value="family">Family truth</option><option value="cultural">Cultural truth</option></select><button class="primary" onclick="submitTruth()">Submit Truth for Review</button><p class="small review-first-note">Enters Review before going public.</p></div></details>${_isAdm?renderTruthAdminBar(_artCnt,_brdCnt,_perCnt):''}${_isAdm?renderTruthFilterBar(truths):''}<div id="truth-grid-container" class="grid truth-grid">${applyTruthAdminFilter(truths).map(t=>truthCard(t)).join('')||'<div class="panel"><div class="empty-state"><p>No truths match this view.</p><p class="small">Use the form above to record a statement that circulates as fact — a slogan, doctrine, or inherited certainty. These are not automatically verified.</p></div></div>'}</div>`}catch(e){renderError(e)}}
function isTruthPersonalBelief(t){return t.truthType==='personal-belief'||String(t.origin||'').toLowerCase().includes('belief snapshot')||/belief engine profile/i.test(t.statement||'');}
function isTruthArtifact(t){const s=String(t.statement||'').trim();if(s.length<4)return true;if(/^(statement|slogan|truth|claim|placeholder|test|demo|example|sample|label|title)$/i.test(s))return true;const letters=s.replace(/[^a-z]/gi,'').toLowerCase();if(letters.length>6){const vowels=(letters.match(/[aeiou]/g)||[]).length;if(vowels/letters.length<0.12)return true;}if(/^(.{2,5})\1{2,}$/i.test(s.replace(/[\s-]/g,'')))return true;return false;}
function isTruthBorderlineArtefact(t){if(isTruthArtifact(t))return false;const s=String(t.statement||'').trim();if(s.length<2)return false;const words=s.split(/\s+/);if(words.length>=2&&words.length<=5&&s.length<=40&&s===s.toUpperCase()&&/[A-Z]/.test(s))return true;const alpha=(s.match(/[a-zA-Z]/g)||[]).length;if(s.replace(/\s/g,'').length>4&&alpha/s.replace(/\s/g,'').length<0.5)return true;return false;}
function applyTruthAdminFilter(list){const f=truthAdminFilter||'all';if(f==='artefacts')return list.filter(isTruthArtifact);if(f==='borderline')return list.filter(t=>isTruthBorderlineArtefact(t)&&!isTruthArtifact(t));if(f==='personal')return list.filter(isTruthPersonalBelief);if(f==='clean')return list.filter(t=>!isTruthArtifact(t)&&!isTruthBorderlineArtefact(t)&&!isTruthPersonalBelief(t));return list;}
function renderTruthAdminBar(artefactCount,borderlineCount,personalCount){return`<div class="truth-admin-bar" style="grid-column:1/-1"><span>⚙</span> <b>Admin Truth tools</b> — <span class="truth-admin-stat">${artefactCount} artefact${artefactCount===1?'':'s'}</span> · <span class="truth-admin-stat">${borderlineCount} borderline</span> · <span class="truth-admin-stat">${personalCount} personal belief</span><span class="truth-admin-bar-hint">Artefacts: archive button active. Borderline: advisory badge only. Personal: policy deferred.</span></div>`;}
function renderTruthFilterBar(list){const counts={all:list.length,artefacts:list.filter(isTruthArtifact).length,borderline:list.filter(t=>isTruthBorderlineArtefact(t)&&!isTruthArtifact(t)).length,personal:list.filter(isTruthPersonalBelief).length,clean:list.filter(t=>!isTruthArtifact(t)&&!isTruthBorderlineArtefact(t)&&!isTruthPersonalBelief(t)).length};const defs=[['all','All'],['artefacts','Artefacts'],['borderline','Borderline'],['personal','Personal'],['clean','Clean']];const chips=defs.map(([f,label])=>{const n=counts[f];const active=truthAdminFilter===f;return`<button class="truth-filter-chip${active?' truth-filter-chip-active':''}" onclick="setTruthAdminFilter('${f}')">${label}${n>0?` <span class="truth-filter-count">${n}</span>`:''}</button>`}).join('');return`<div id="truth-filter-bar" class="truth-filter-bar" style="grid-column:1/-1">${chips}</div>`;}
async function setTruthAdminFilter(f){truthAdminFilter=f||'all';await renderTruths();}
function copyTruthId(id){navigator.clipboard.writeText(id).then(()=>toast('Truth ID copied')).catch(()=>toast('Copy failed — select the ID manually'));}
async function archiveTruthArtefact(id){if(!adminToken()){toast('Admin token required');return;}const truth=(truths||[]).find(t=>t.id===id);const statement=truth?truth.statement:id;if(!confirm('Archive this Truth artefact?\n\n"'+statement+'"\nID: '+id+'\n\nThis will reject then archive it.'))return;try{await api('/api/review/decision',{method:'POST',headers:adminHeaders(),body:JSON.stringify({targetType:'truth',targetId:id,decision:'rejected'})});await api('/api/review/cleanup',{method:'POST',headers:adminHeaders(),body:JSON.stringify({target_type:'truth',target_id:id,junk_override:true,reason:'Admin UI artefact cleanup'})});toast('Truth artefact archived');await renderTruths()}catch(e){toast(e.message||'Archive failed')}}
// D-137C: derive the state of a truth's pressure-test claim (if any) so the card
// can show a state-specific badge and button instead of a generic "claim derived"
// chip + always-fresh-looking submit button. truths.linked_claim_id always points
// to the single canonical derived claim (see src/truths.js listTruths comment).
const TRUTH_CLAIM_STATE_BADGES={public:['CLAIM PUBLIC','b-green'],review:['CLAIM IN REVIEW','b-yellow'],rejected:['CLAIM REJECTED','b-red'],archived:['CLAIM ARCHIVED','b-muted'],duplicate:['CLAIM DUPLICATE','b-purple']};
function truthClaimStateMeta(t){const claimId=t.linkedClaimId||t.linked_claim_id||null;if(!claimId)return{state:null,badgeHtml:'',btnClass:'primary',btnLabel:'Pressure-test as Claim →',btnAction:`convertTruth('${esc(t.id)}')`,note:'Creates a claim for review — does not prove this truth.'};const state=t.linkedClaimReviewState||t.linked_claim_review_state||'review';const[label,cls]=TRUTH_CLAIM_STATE_BADGES[state]||['CLAIM '+state.toUpperCase(),'b-muted'];const badgeHtml=`<span class="badge ${cls} truth-claim-state-badge">${esc(label)}</span>`;if(state==='public')return{state,badgeHtml,btnClass:'primary',btnLabel:'Open Claim Study →',btnAction:`openTruthClaimStudy('${esc(claimId)}')`,note:'Opens the existing public claim — this truth itself remains unaffected.'};if(state==='review')return{state,badgeHtml,btnClass:'truth-claim-btn-muted',btnLabel:'Already in Review',btnAction:`convertTruth('${esc(t.id)}')`,note:'This truth remains public. The derived pressure-test claim is already in review — clicking does not create a new submission.'};const labelByState={rejected:'Rejected pressure-test',archived:'Archived pressure-test',duplicate:'Duplicate pressure-test'};const btnLabel=labelByState[state]||('Pressure-test '+state);return{state,badgeHtml,btnClass:'truth-claim-btn-muted',btnLabel,btnAction:`convertTruth('${esc(t.id)}')`,note:`This truth remains public. Only the derived pressure-test claim is ${state} — clicking does not create a new submission.`};}
async function openTruthClaimStudy(claimId){lastModeBeforeStudy='truths';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(claimId)}
function truthCard(t){const metaParts=[t.category||'general',t.origin&&t.origin!=='unknown'?'origin: '+t.origin:null,'by '+(t.handle||'anon')].filter(Boolean).map(esc).join(' · ');const pressureStat=(t.pressureScore||0)>0?`<span class="truth-stat truth-stat-pressure" title="Pressure score">⊘ ${esc(t.pressureScore)} pressure</span>`:'';const personalBelief=isTruthPersonalBelief(t);const artifact=isTruthArtifact(t);const isAdmin=!!adminToken();const borderline=isAdmin&&isTruthBorderlineArtefact(t)&&!artifact;const idSuffix=t.id?t.id.slice(-8):'';const claimMeta=truthClaimStateMeta(t);return`<article class="card truth-card${artifact?' truth-card-artifact':''}"><div class="truth-card-head"><span class="badge b-yellow">${esc(t.truthType||'truth')}</span><span class="badge b-muted truth-not-verified">not verified</span>${personalBelief?`<span class="badge b-muted truth-personal-badge">personal belief</span>`:''} ${artifact?`<span class="badge b-muted truth-artifact-badge">? artefact</span>`:''} ${borderline?`<span class="badge b-muted truth-borderline-badge">? borderline</span>`:''} ${t.confidenceLabel?`<span class="badge">${esc(t.confidenceLabel)}</span>`:''} ${claimMeta.badgeHtml}</div><h3 class="truth-title">${esc(cleanClaimLabel(t.statement))}</h3>${reviewStatusBadge(t,false,true)}<p class="small truth-meta">${metaParts}</p><div class="truth-stats"><span class="truth-stat" title="Reinforcement count">↻ ${esc(t.repetitionScore||1)} repeated</span>${pressureStat}</div>${t.id?(isAdmin?`<p class="small truth-id-line truth-id-admin"><code class="truth-id-full" title="${esc(t.id)}">${esc(t.id)}</code><button class="btn-mini btn-copy-id" onclick="copyTruthId('${esc(t.id)}')" title="Copy full truth ID">copy id</button></p>`:`<p class="small truth-id-line">id: …${esc(idSuffix)}</p>`):''}${isAdmin&&artifact?`<p class="small truth-admin-actions"><button class="btn-mini btn-archive-artifact" onclick="archiveTruthArtefact('${esc(t.id)}')" title="Reject and archive this artefact">archive artefact</button></p>`:''}<div class="actions"><button class="${claimMeta.btnClass}" onclick="${claimMeta.btnAction}" title="${esc(claimMeta.note)}">${esc(claimMeta.btnLabel)}</button></div><p class="small truth-convert-note">${esc(claimMeta.note)}</p></article>`}

// D-137D/E: My HumanX personal dashboard frontend.
// Reads-only against GET /api/my-humanx, which is always scoped to the
// requester's own x-humanx-user identity (D-137B). No share buttons, no
// public profile, no target-user parameter — this page only ever shows
// the current browser's own content.
const ME_STATE_LABELS={public:'Public',review:'Review',rejected:'Rejected',archived:'Archived',duplicate:'Duplicate'};
const ME_STATE_CLR={public:'b-green',review:'b-yellow',rejected:'b-red',archived:'b-muted',duplicate:'b-purple'};
const ME_VISIBLE_CAP=5;
const ME_FILTER_STATES=['all','public','review','rejected','archived','duplicate'];
let meData=null;
let meStateFilter='all';
let meExpanded={};
async function openMyClaimStudy(claimId){lastModeBeforeStudy='me';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(claimId)}
function meRerender(){if(meData)document.getElementById('main').innerHTML=renderMeHtml(meData)}
function meSetFilter(state){meStateFilter=ME_FILTER_STATES.includes(state)?state:'all';meRerender()}
function meToggleExpand(key){meExpanded[key]=!meExpanded[key];meRerender()}
function meFilterRows(rows){if(meStateFilter==='all')return rows||[];return(rows||[]).filter(r=>(r.review_state||'review')===meStateFilter)}
function meVisibleSlice(key,rows){return meExpanded[key]?rows:rows.slice(0,ME_VISIBLE_CAP)}
function meShowAllControl(key,total){if(total<=ME_VISIBLE_CAP)return'';const exp=!!meExpanded[key];return`<button class="btn-mini me-toggle" onclick="meToggleExpand('${key}')">${exp?'Show less':'Show all ('+total+')'}</button>`}
function meFilterBarHtml(){return`<div class="me-filter-bar">${ME_FILTER_STATES.map(s=>`<button class="me-filter-btn ${meStateFilter===s?'active':''}" onclick="meSetFilter('${s}')">${s==='all'?'All':esc(ME_STATE_LABELS[s]||s)}</button>`).join('')}</div>`}
function meAccountCardHtml(u){if(!u)return'<div class="panel"><p class="small">Account info unavailable.</p></div>';const verified=!!u.verified;return`<div class="panel me-account-card"><div class="me-account-head"><span class="badge ${verified?'b-green':'b-muted'}">${verified?'Verified':'Anonymous'}</span></div><p class="me-account-name">${esc(u.display_name||u.handle||'')}</p>${verified&&u.email?`<p class="small me-account-sub">${esc(u.email)}</p>`:''}<p class="small me-account-sub">Handle: ${esc(u.handle||'')}</p><p class="small me-account-sub">User ID: <code>${esc(u.id||'')}</code></p><div class="me-account-actions"><button class="btn-mini" onclick="exportMyHumanXData()">Export my data (JSON)</button></div></div>`}
async function exportMyHumanXData(){try{const data=await api('/api/my-humanx/export');const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`humanx-export-${(data.user&&data.user.id)||'me'}.json`;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(url);toast('Export downloaded.')}catch(e){toast(e.message||'Export failed.')}}
// D-140B: Profile Settings panel — foundation only. Saving here does not make
// anything public yet; there is no public read route or public page in this
// patch (see docs/D140A audit). The Copy share link button only ever reflects
// the last *saved* state, never the unsaved form values.
// D-141B: 1-2 sample public items for the owner-side preview, drawn only from
// already-loaded /api/my-humanx data (meData) — no new backend call. Claims/
// truths only, filtered to review_state==='public' (which also excludes
// archived-by-user rows, since archiving flips review_state to 'archived').
function meProfilePublicSamples(){const claims=(meData?.claims||[]).filter(c=>(c.review_state||'review')==='public').slice(0,2).map(c=>({type:'Claim',text:shortText(cleanClaimLabel(c.claim||''),80)}));const truths=(meData?.truths||[]).filter(t=>(t.review_state||'review')==='public').slice(0,2).map(t=>({type:'Truth',text:shortText(cleanClaimLabel(t.statement||''),80)}));return[...claims,...truths].slice(0,2)}
function meProfilePreviewSampleHtml(samples){if(!samples||!samples.length)return'';return`<div class="pp-item-list">${samples.map(s=>`<div class="pp-item-row"><span class="small me-item-meta">${esc(s.type)}</span><span class="me-item-text">${esc(s.text)}</span></div>`).join('')}</div>`}
// D-142B: computes the exact public-safe snapshot summary client-side from
// already-loaded meData.belief_snapshots — same narrow field set the backend
// returns via GET /api/u/:slug's sharedSnapshot, so the owner preview matches
// reality. Never reads dimensions_json, raw_json, stress_points_json, or
// full contradictions_json text.
function meSharedSnapshotSummary(){const rows=meData?.belief_snapshots||[];const shared=rows.find(s=>!!s.public_summary_enabled);if(!shared)return null;let topAlignmentName=null;const topBeliefs=meSafeParseJson(shared.top_beliefs_json,[]);if(Array.isArray(topBeliefs)&&topBeliefs[0]&&topBeliefs[0].name)topAlignmentName=String(topBeliefs[0].name);return{label:shared.label||null,dominantPattern:shared.dominant_pattern||null,stabilityScore:shared.stability_score||0,opennessScore:shared.openness_score||0,pressureScore:shared.pressure_score||0,topAlignmentName,contradictionCount:shared.contradiction_count||0}}
function meSharedSnapshotCardHtml(s){if(!s)return'';return`<div class="pp-card pp-snapshot-card"><p class="small pp-disclaimer">One snapshot, shared by choice — not your complete profile.</p><p class="small pp-disclaimer">Pattern observations from your own answers, not a diagnosis or personality test.</p>${s.label?`<p class="pp-snapshot-label">${esc(s.label)}</p>`:''}<p class="small pp-snapshot-pattern-label">Self-reported dominant pattern</p><p class="me-mirror-pattern">${esc(s.dominantPattern||'Pattern not labeled')}</p>${meter('Stability',s.stabilityScore)}${meter('Openness',s.opennessScore)}${meter('Pressure',s.pressureScore)}${s.topAlignmentName?`<p class="small">Top alignment: ${esc(s.topAlignmentName)}</p>`:''}<p class="small">${esc(s.contradictionCount)} tension${s.contradictionCount===1?'':'s'} noted</p></div>`}
// D-142C: shows a compact preview of the selected snapshot, or a clear
// "nothing will appear" message — and frames sharing as optional and
// separate from the profile_public toggle, since the owner could enable
// one without the other.
function meSharedSnapshotPreviewBlockHtml(){const intro='<p class="small">Belief snapshot sharing is optional and separate from your public profile toggle.</p>';const s=meSharedSnapshotSummary();if(!s)return`${intro}<p class="small pp-empty">No belief snapshot will appear publicly.</p>`;return`${intro}${meSharedSnapshotCardHtml(s)}`}
function meProfilePreviewBodyHtml(slug,bio,isPublic,counts,samples){if(!isPublic)return'<p class="small pp-empty">Profile is off — nothing public yet.</p>';const c=counts||{};const countsHtml=`<span class="badge">Claims ${esc(c.claims?.public||0)}</span><span class="badge">Truths ${esc(c.truths?.public||0)}</span><span class="badge">Evidence ${esc(c.evidence?.public||0)}</span><span class="badge">Pressure ${esc(c.pressure?.public||0)}</span>`;return`<p class="me-profile-preview-slug">/u/${esc(slug||'your-slug')}</p>${bio?`<p class="small">${esc(shortText(bio,240))}</p>`:''}<div class="me-mirror-chip-row">${countsHtml}</div><p class="small pp-counts-note">Counts reflect public, non-archived activity only.</p>${meSharedSnapshotPreviewBlockHtml()}${meProfilePreviewSampleHtml(samples)}`}
function meUpdateProfilePreview(){const slug=(document.getElementById('meProfileSlugInput')?.value||'').trim();const bio=(document.getElementById('meProfileBioInput')?.value||'').trim();const isPublic=!!document.getElementById('meProfilePublicToggle')?.checked;const body=document.getElementById('meProfilePreviewBody');if(body)body.innerHTML=meProfilePreviewBodyHtml(slug,bio,isPublic,meData?.counts,meProfilePublicSamples());const copyBtn=document.getElementById('meProfileCopyBtn');if(copyBtn){const canCopy=isPublic&&!!slug;copyBtn.disabled=!canCopy;copyBtn.style.display=canCopy?'':'none'}}
async function saveProfileSettingsUI(){const isPublic=!!document.getElementById('meProfilePublicToggle')?.checked;const slug=(document.getElementById('meProfileSlugInput')?.value||'').trim();const bio=(document.getElementById('meProfileBioInput')?.value||'').trim();try{await api('/api/my-humanx/profile-settings',{method:'POST',body:JSON.stringify({profile_public:isPublic,profile_slug:slug,profile_bio:bio})});toast('Profile link foundation saved. Public page comes next.');await renderMe()}catch(e){toast(e.message||'Could not save profile settings.')}}
// D-143B: shares the real /u/:slug path (server-rendered OG meta tags) now
// that the Worker serves it — the #/u/:slug hash route still works as a
// fallback for any in-app link that doesn't go through this function.
function meCopyProfileLink(){const isPublic=!!document.getElementById('meProfilePublicToggle')?.checked;const slug=(document.getElementById('meProfileSlugInput')?.value||'').trim();if(!isPublic||!slug)return;const link=`${location.origin}/u/${encodeURIComponent(slug)}`;if(navigator.clipboard?.writeText){navigator.clipboard.writeText(link).then(()=>toast('Profile link copied.')).catch(()=>toast('Copy failed — select the link manually.'))}else{toast('Copy failed — select the link manually.')}}
function meProfileSettingsHtml(data){const u=data.user||{};const isPublic=!!u.profile_public;const slug=u.profile_slug||'';const bio=u.profile_bio||'';const canCopy=isPublic&&!!slug;return`<div class="panel me-profile-settings"><h3>Profile Settings</h3><p class="small me-mirror-guardrail">Off by default. Nothing about your account is public until you turn this on and save.</p><label class="me-profile-toggle"><input type="checkbox" id="meProfilePublicToggle" ${isPublic?'checked':''} onchange="meUpdateProfilePreview()"> Make my profile public</label><label class="small" for="meProfileSlugInput">Profile link slug</label><input id="meProfileSlugInput" type="text" value="${esc(slug)}" placeholder="your-slug" oninput="meUpdateProfilePreview()"><label class="small" for="meProfileBioInput">Bio</label><textarea id="meProfileBioInput" maxlength="240" oninput="meUpdateProfilePreview()">${esc(bio)}</textarea><div class="me-profile-preview"><p class="small">This is what others would see if you publish.</p><div id="meProfilePreviewBody">${meProfilePreviewBodyHtml(slug,bio,isPublic,data.counts,meProfilePublicSamples())}</div></div><div class="me-profile-actions"><button class="primary btn-mini" onclick="saveProfileSettingsUI()">Save</button><button class="btn-mini" id="meProfileCopyBtn" onclick="meCopyProfileLink()" ${canCopy?'':'disabled'} style="${canCopy?'':'display:none'}">Copy share link</button></div></div>`}
// D-140C: public, no-auth, read-only profile view rendered from the #/u/:slug
// hash route. No edit/archive/export controls, no owner-only Me data — this
// renders strictly from the GET /api/u/:slug response.
async function openPublicProfileClaimStudy(claimId){lastModeBeforeStudy='arena';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(claimId)}
function renderPublicProfileClaimsHtml(rows){if(!rows||!rows.length)return'<p class="small pp-empty">No public claims yet.</p>';return`<div class="pp-item-list">${rows.map(c=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(cleanClaimLabel(c.claim||''),140))}</span><span class="small me-item-meta">${esc(c.category||'')}</span><button class="btn-mini" onclick="openPublicProfileClaimStudy('${esc(c.id)}')">Open Study →</button></div>`).join('')}</div>`}
function renderPublicProfileTruthsHtml(rows){if(!rows||!rows.length)return'<p class="small pp-empty">No public truths yet.</p>';return`<div class="pp-item-list">${rows.map(t=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(cleanClaimLabel(t.statement||''),140))}</span><span class="small me-item-meta">${esc(t.category||'')}</span></div>`).join('')}</div>`}
function renderPublicProfileEvidenceHtml(rows){if(!rows||!rows.length)return'<p class="small pp-empty">No public evidence yet.</p>';return`<div class="pp-item-list">${rows.map(e=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(e.title||'Evidence',140))}</span><span class="small me-item-meta">${esc(evidenceQualityLabel(e.quality||''))}</span></div>`).join('')}</div>`}
function renderPublicProfilePressureHtml(rows){if(!rows||!rows.length)return'<p class="small pp-empty">No public pressure points yet.</p>';return`<div class="pp-item-list">${rows.map(p=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(p.title||'Pressure point',140))}</span><span class="small me-item-meta">severity ${esc(p.severity||1)}</span></div>`).join('')}</div>`}
// D-142B: optional shared-snapshot card, rendered only when the API returned
// one (i.e. the owner explicitly selected a snapshot AND the profile is
// public). Third-person wording since this describes someone else's choice
// to a visitor — mirrors meSharedSnapshotCardHtml's owner-facing copy but
// is intentionally a separate function/string, not shared, so the two
// audiences' wording can be reviewed and changed independently.
function renderPublicProfileSnapshotHtml(s){if(!s)return'';const created=s.createdAt?new Date(s.createdAt).toLocaleDateString():null;return`<div class="panel pp-card pp-snapshot-card"><h3>Shared Belief Snapshot</h3><p class="small pp-disclaimer">A snapshot this person chose to share — pattern observations from their own self-submitted answers, not a diagnosis or personality test.</p><p class="small pp-disclaimer">One snapshot, shared by choice — not their complete profile.</p>${s.label?`<p class="pp-snapshot-label">${esc(s.label)}</p>`:''}<p class="small pp-snapshot-pattern-label">Self-reported dominant pattern</p><p class="me-mirror-pattern">${esc(s.dominantPattern||'Pattern not labeled')}</p>${meter('Stability',s.stabilityScore)}${meter('Openness',s.opennessScore)}${meter('Pressure',s.pressureScore)}${s.topAlignmentName?`<p class="small">Top alignment: ${esc(s.topAlignmentName)}</p>`:''}<p class="small">${esc(s.contradictionCount)} tension${s.contradictionCount===1?'':'s'} noted</p>${created?`<p class="small pp-snapshot-date">Shared snapshot recorded ${esc(created)}</p>`:''}</div>`}
function renderPublicProfileHtml(p){const counts=p.counts||{};const isOwner=!!(meData&&meData.user&&meData.user.profile_slug&&meData.user.profile_slug===p.slug);const backFn=isOwner?"setMode('me')":"setMode('home')";const backLabel=isOwner?'← Back to Me':'← Back to Home';return`<div class="section-head"><h2>Public Profile</h2></div><div class="panel pp-header pp-card"><p class="pp-display-name">${esc(p.displayName||'anon')}</p><p class="small pp-slug">/u/${esc(p.slug||'')}</p>${p.bio?`<p class="small pp-bio">${esc(p.bio)}</p>`:''}<p class="small pp-disclaimer">Public profile shows selected public HumanX activity only. It is not a truth ruling or personality diagnosis.</p></div><div class="panel pp-card pp-counts-card"><h3>Public Activity</h3><div class="me-mirror-chip-row"><span class="badge">Claims ${esc(counts.claims||0)}</span><span class="badge">Truths ${esc(counts.truths||0)}</span><span class="badge">Evidence ${esc(counts.evidence||0)}</span><span class="badge">Pressure ${esc(counts.pressure||0)}</span></div><p class="small pp-counts-note">Counts reflect public, non-archived activity only.</p></div>${renderPublicProfileSnapshotHtml(p.sharedSnapshot)}<div class="panel pp-section"><h3>Recent Public Claims</h3>${renderPublicProfileClaimsHtml(p.recentClaims)}</div><div class="panel pp-section"><h3>Recent Public Truths</h3>${renderPublicProfileTruthsHtml(p.recentTruths)}</div><div class="panel pp-section"><h3>Recent Public Evidence</h3>${renderPublicProfileEvidenceHtml(p.recentEvidence)}</div><div class="panel pp-section"><h3>Recent Public Pressure</h3>${renderPublicProfilePressureHtml(p.recentPressure)}</div><div class="actions" style="margin-top:10px"><button class="primary" onclick="${backFn}">${backLabel}</button></div>`}
async function renderPublicProfile(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML='';document.getElementById('side-tools').style.display='none';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('main').innerHTML='<div class="panel"><h2>Loading profile…</h2></div>';try{const data=await api(`/api/u/${encodeURIComponent(publicProfileSlug||'')}`);document.getElementById('main').innerHTML=renderPublicProfileHtml(data.profile||{})}catch(e){document.getElementById('main').innerHTML=`<div class="panel"><h3>Profile not found or not public.</h3><div class="actions" style="margin-top:10px"><button class="primary" onclick="setMode('home')">← Back to Home</button></div></div>`}}
function meArchiveErrorMessage(code){if(code==='STILL_REFERENCED')return'Cannot archive — this is still used by another public claim.';if(code==='PROTECTED')return'This item is protected and cannot be archived.';if(code==='NOT_FOUND_OR_NOT_OWNED')return'Item not found or not owned by you.';return code||'Archive failed.'}
function meFindItemLabel(targetType,targetId){if(!meData)return targetId;const list=targetType==='claim'?meData.claims:targetType==='truth'?meData.truths:targetType==='evidence'?meData.evidence:targetType==='pressure'?meData.pressure:[];const item=(list||[]).find(x=>x.id===targetId);if(!item)return targetId;if(targetType==='claim')return shortText(cleanClaimLabel(item.claim||''),80);if(targetType==='truth')return shortText(cleanClaimLabel(item.statement||''),80);return shortText(item.title||'',80)}
function meArchiveItemUI(targetType,targetId){const label=meFindItemLabel(targetType,targetId);hxModal({title:'Archive item',body:`<p class="small" style="margin:0 0 8px">Archive <strong>${esc(label)}</strong>? It will be hidden from My HumanX and public listings. This does not delete it — no hard delete in My HumanX yet.</p>`,confirmLabel:'Archive',cancelLabel:'Cancel',onConfirm:async(close)=>{close();try{await api('/api/my-humanx/archive',{method:'POST',body:JSON.stringify({targetType,targetId})});toast('Archived.');await renderMe()}catch(e){toast(meArchiveErrorMessage(e.message))}}})}
function meCountsRow(label,counts){if(!counts)return'';const chips=Object.keys(ME_STATE_LABELS).map(s=>`<span class="badge ${ME_STATE_CLR[s]} me-count-chip">${esc(ME_STATE_LABELS[s])}: ${esc(counts[s]||0)}</span>`).join('');return`<div class="me-count-row"><span class="me-count-label">${esc(label)}</span><div class="me-count-chips">${chips}</div></div>`}
function meRecentClaimsHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No claims match this filter.</p>';return`<div class="me-item-list">${rows.map(c=>{const state=c.review_state||'review';const isPublic=state==='public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(c.updated_at||c.created_at);return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(cleanClaimLabel(c.claim||''),140))}</span><span class="small me-item-meta">${esc(when)}</span>${isPublic?`<button class="btn-mini" onclick="openMyClaimStudy('${esc(c.id)}')">Open Study →</button>`:''}${!isArchived?`<button class="btn-mini danger" onclick="meArchiveItemUI('claim','${esc(c.id)}')">Archive</button>`:''}</div>`}).join('')}</div>`}
function meRecentTruthsHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No truths match this filter.</p>';return`<div class="me-item-list">${rows.map(t=>{const state=t.review_state||'review';const isPublic=state==='public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(t.updated_at||t.created_at);return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(cleanClaimLabel(t.statement||''),140))}</span><span class="small me-item-meta">${esc(when)}</span>${isPublic?`<button class="btn-mini" onclick="setMode('truths')">View in Truths →</button>`:''}${!isArchived?`<button class="btn-mini danger" onclick="meArchiveItemUI('truth','${esc(t.id)}')">Archive</button>`:''}</div>`}).join('')}</div>`}
function meRecentEvidenceHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No evidence matches this filter.</p>';return`<div class="me-item-list">${rows.map(e=>{const state=e.review_state||'public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(e.created_at);const type=e.type||'evidence';return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(e.title||'Evidence',140))}</span><span class="small me-item-meta">${esc(type)} · ${esc(when)}</span>${e.claim_id?`<code class="me-item-parent" title="Parent claim — not opened automatically, may not be public">claim: ${esc(e.claim_id)}</code>`:''}${!isArchived?`<button class="btn-mini danger" onclick="meArchiveItemUI('evidence','${esc(e.id)}')">Archive</button>`:''}</div>`}).join('')}</div>`}
function meRecentPressureHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No pressure points match this filter.</p>';return`<div class="me-item-list">${rows.map(p=>{const state=p.review_state||'public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(p.updated_at||p.created_at);return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(p.title||'Pressure point',140))}</span><span class="small me-item-meta">${esc(when)}</span>${p.claim_id?`<code class="me-item-parent" title="Parent claim — not opened automatically, may not be public">claim: ${esc(p.claim_id)}</code>`:''}${!isArchived?`<button class="btn-mini danger" onclick="meArchiveItemUI('pressure','${esc(p.id)}')">Archive</button>`:''}</div>`}).join('')}</div>`}
// D-142B: snapshot sharing is opt-in, per-snapshot, and exclusive — selecting
// one clears any other (enforced server-side too, see saveProfileSettings()).
// This radio group never touches profile_public/slug/bio; it always reuses
// the currently-saved values from meData.user so a sharing change can't
// accidentally publish (or unpublish) the rest of the profile.
async function meShareSnapshotUI(snapshotId){const u=meData?.user||{};try{await api('/api/my-humanx/profile-settings',{method:'POST',body:JSON.stringify({profile_public:!!u.profile_public,profile_slug:u.profile_slug||'',profile_bio:u.profile_bio||'',shared_snapshot_id:snapshotId})});toast(snapshotId?'Snapshot shared on your public profile.':'Sharing cleared — no snapshot is shared.');await renderMe()}catch(e){toast(e.message||'Could not update snapshot sharing.')}}
function meBeliefSnapshotsHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No belief snapshots yet.</p>';const anyShared=rows.some(s=>!!s.public_summary_enabled);const helper='<p class="small me-snapshot-helper">Choose one snapshot to show on your public profile. You can also share none.</p>';const rowsHtml=rows.map(s=>{const isShared=!!s.public_summary_enabled;return`<div class="me-item-row${isShared?' me-item-row-selected':''}"><span class="me-item-text">${esc(s.label||'Snapshot')}</span><span class="small me-item-meta">stability ${esc(s.stability_score??0)} · openness ${esc(s.openness_score??0)} · pressure ${esc(s.pressure_score??0)} · ${esc(reviewAge(s.created_at))}</span><label class="me-snapshot-share small"><input type="radio" name="meSharedSnapshot" ${isShared?'checked':''} onclick="meShareSnapshotUI('${esc(s.id)}')"> Share on public profile</label></div>`}).join('');const noneRow=`<div class="me-item-row me-snapshot-share-none${!anyShared?' me-item-row-selected':''}"><label class="me-snapshot-share small"><input type="radio" name="meSharedSnapshot" ${!anyShared?'checked':''} onclick="meShareSnapshotUI(null)"> Do not share a snapshot</label></div>`;return`${helper}<div class="me-item-list">${rowsHtml}${noneRow}</div>`}
// D-139B: Belief Mirror panel — entirely client-side synthesis of already-stored
// data from GET /api/my-humanx. No AI/LLM call, no new endpoint. Every card is
// framed as a tentative pattern observation, never a diagnosis or verdict —
// see docs/D139A audit wording guardrails.
function meSafeParseJson(raw,fallback){if(raw==null)return fallback;if(typeof raw==='object')return raw;try{const v=JSON.parse(raw);return v==null?fallback:v}catch{return fallback}}
function meMirrorGuardrailHtml(){return'<p class="small me-mirror-guardrail">Pattern observations from your own answers and submissions — not a diagnosis or personality test.</p>'}
function meMirrorLatestCardHtml(latest){if(!latest)return'';return`<div class="me-mirror-card"><h4>Latest snapshot</h4><p class="me-mirror-pattern">${esc(latest.dominant_pattern||'Pattern not labeled')}</p>${meter('Stability',latest.stability_score)}${meter('Openness',latest.openness_score)}${meter('Pressure',latest.pressure_score)}</div>`}
function meMirrorDriftCardHtml(latest,previous){if(!latest||!previous)return'';const d=(a,b)=>{const v=(Number(a)||0)-(Number(b)||0);return(v>0?'+':'')+v};return`<div class="me-mirror-card"><h4>Recent drift</h4><p class="small">Since your last check-in:</p><p class="me-mirror-drift-row">Stability <b>${esc(d(latest.stability_score,previous.stability_score))}</b></p><p class="me-mirror-drift-row">Openness <b>${esc(d(latest.openness_score,previous.openness_score))}</b></p><p class="me-mirror-drift-row">Pressure <b>${esc(d(latest.pressure_score,previous.pressure_score))}</b></p></div>`}
function meMirrorTopCategories(claims,truths){const counts={};const add=v=>{const c=String(v||'').trim();if(!c)return;counts[c]=(counts[c]||0)+1};(claims||[]).forEach(c=>add(c.category));(truths||[]).forEach(t=>add(t.category));return Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,3)}
function meMirrorCategoriesCardHtml(claims,truths){const top=meMirrorTopCategories(claims,truths);if(!top.length)return'';return`<div class="me-mirror-card"><h4>Recurring categories</h4><div class="me-mirror-chip-row">${top.map(([cat,n])=>`<span class="badge b-blue">${esc(cat)} · ${esc(n)}</span>`).join('')}</div></div>`}
function meMirrorBalanceCardHtml(pressure,evidence){const sevCounts={};(pressure||[]).forEach(p=>{const s=Number(p.severity)||0;if(s>0)sevCounts[s]=(sevCounts[s]||0)+1});const qualCounts={};(evidence||[]).forEach(e=>{const q=e.type||e.quality||'';if(!q)return;const lbl=evidenceQualityLabel(q);qualCounts[lbl]=(qualCounts[lbl]||0)+1});const sevChips=Object.keys(sevCounts).sort().map(s=>`<span class="badge">sev ${esc(s)} · ${esc(sevCounts[s])}</span>`).join('');const qualChips=Object.keys(qualCounts).map(q=>`<span class="badge">${esc(q)} · ${esc(qualCounts[q])}</span>`).join('');if(!sevChips&&!qualChips)return'';return`<div class="me-mirror-card"><h4>Pressure / evidence balance</h4>${sevChips?`<p class="small">Pressure severity</p><div class="me-mirror-chip-row">${sevChips}</div>`:''}${qualChips?`<p class="small">Evidence quality</p><div class="me-mirror-chip-row">${qualChips}</div>`:''}</div>`}
function meMirrorTensionsCardHtml(latest){if(!latest)return'';const list=meSafeParseJson(latest.contradictions_json,[]);if(!Array.isArray(list)||!list.length)return'';const items=list.slice(0,3).map(t=>{if(typeof t==='string')return t;if(t&&typeof t==='object')return[t.title,t.desc||t.description].filter(Boolean).join(': ');return''}).filter(Boolean);if(!items.length)return'';return`<div class="me-mirror-card"><h4>Tensions</h4><p class="small">Patterns the engine flagged in your answers, not facts about you.</p><ul class="me-mirror-tension-list">${items.map(t=>`<li>${esc(shortText(t,160))}</li>`).join('')}</ul></div>`}
function meMirrorQuestions(latest,evidenceCount){const qs=[];const pressureScore=Number(latest?.pressure_score)||0;const contradictions=meSafeParseJson(latest?.contradictions_json,[]);if(pressureScore>65)qs.push('What belief have I not pressure-tested yet?');if(Array.isArray(contradictions)&&contradictions.length>0)qs.push('Which tension would I investigate first?');if(evidenceCount<3)qs.push('What would change my mind?');return qs.slice(0,3)}
function meMirrorQuestionsCardHtml(latest,evidenceCount){const qs=meMirrorQuestions(latest,evidenceCount);if(!qs.length)return'';return`<div class="me-mirror-card"><h4>Questions to ask yourself</h4><ul class="me-mirror-question-list">${qs.map(q=>`<li>${esc(q)}</li>`).join('')}</ul></div>`}
function meMirrorHtml(data){const snapshots=data.belief_snapshots||[];if(!snapshots.length){return`<div class="panel"><h3>Belief Mirror</h3>${meMirrorGuardrailHtml()}<p class="small me-empty">Take the Belief Engine to start your Mirror.</p><button class="btn-mini" onclick="location.href='/apps/humanx-belief-engine/'">Open Belief Engine →</button></div>`}const latest=snapshots[0];const previous=snapshots[1]||null;const evidenceCount=(data.evidence||[]).length;const cards=[meMirrorLatestCardHtml(latest),meMirrorDriftCardHtml(latest,previous),meMirrorCategoriesCardHtml(data.claims,data.truths),meMirrorBalanceCardHtml(data.pressure,data.evidence),meMirrorTensionsCardHtml(latest),meMirrorQuestionsCardHtml(latest,evidenceCount)].filter(Boolean);return`<div class="panel"><h3>Belief Mirror</h3>${meMirrorGuardrailHtml()}<div class="me-mirror-grid">${cards.join('')}</div></div>`}
function renderMeHtml(data){const u=data.user||{};const counts=data.counts||{};const claims=meFilterRows(data.claims);const truths=meFilterRows(data.truths);const evidence=meFilterRows(data.evidence);const pressure=meFilterRows(data.pressure);const snapshots=data.belief_snapshots||[];return`<div class="section-head"><h2>My HumanX</h2></div>${meAccountCardHtml(u)}${meProfileSettingsHtml(data)}<div class="panel me-counts-panel"><h3>My Content</h3>${meCountsRow('Claims',counts.claims)}${meCountsRow('Truths',counts.truths)}${meCountsRow('Evidence',counts.evidence)}${meCountsRow('Pressure',counts.pressure)}</div>${meFilterBarHtml()}<div class="panel"><h3>Recent Claims</h3>${meRecentClaimsHtml(meVisibleSlice('claims',claims))}${meShowAllControl('claims',claims.length)}</div><div class="panel"><h3>Belief Snapshots</h3>${meBeliefSnapshotsHtml(meVisibleSlice('snapshots',snapshots))}${meShowAllControl('snapshots',snapshots.length)}</div>${meMirrorHtml(data)}<div class="panel"><h3>Recent Truths</h3>${meRecentTruthsHtml(meVisibleSlice('truths',truths))}${meShowAllControl('truths',truths.length)}</div><div class="panel"><h3>Recent Evidence</h3>${meRecentEvidenceHtml(meVisibleSlice('evidence',evidence))}${meShowAllControl('evidence',evidence.length)}</div><div class="panel"><h3>Recent Pressure</h3>${meRecentPressureHtml(meVisibleSlice('pressure',pressure))}${meShowAllControl('pressure',pressure.length)}</div>`}
async function renderMe(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading My HumanX…</h2></div>';try{meData=await api('/api/my-humanx');document.getElementById('main').innerHTML=renderMeHtml(meData)}catch(e){document.getElementById('main').innerHTML=`<div class="panel"><h3>My HumanX unavailable</h3><p class="small">${esc(e.message||e)}</p></div>`}}
function initReviewKb(){if(_reviewKbBound)return;_reviewKbBound=true;document.addEventListener('keydown',function(e){if(mode!=='review')return;const ae=document.activeElement;if(ae&&(ae.tagName==='INPUT'||ae.tagName==='TEXTAREA'||ae.tagName==='SELECT'||ae.isContentEditable))return;if(document.getElementById('hx-modal'))return;if(_reviewKbInFlight)return;const key=e.key;if(key==='Escape'&&inspectedReviewItem){e.preventDefault();inspectReviewItem(inspectedReviewItem.id);return;}if(!inspectedReviewItem)return;const id=inspectedReviewItem.id;const type=inspectedReviewItem.target_type||inspectedReviewItem.targetType||inspectedReviewItem.type||'claim';const vl=applyReviewSort(applyReviewFilter(reviewQueue.review||[]));const _i=vl.findIndex(v=>v.id===id);const _next=_i<vl.length-1?vl[_i+1]:null;const _prev=_i>0?vl[_i-1]:null;if(key===']'||key==='ArrowRight'){e.preventDefault();if(_next)inspectReviewItem(_next.id);return;}if(key==='['||key==='ArrowLeft'){e.preventDefault();if(_prev)inspectReviewItem(_prev.id);return;}if(key==='a'||key==='k'||key==='r'){e.preventDefault();const decision=key==='a'?'public':key==='k'?'review':'rejected';_reviewKbInFlight=true;const _advanceId=(_next?.id||_prev?.id||null);reviewDecisionUI(type,id,decision).then(()=>{if(_advanceId)inspectReviewItem(_advanceId);}).catch(()=>{}).finally(()=>{_reviewKbInFlight=false;});}});}
async function renderReview(){document.body.classList.remove('study-mode');initReviewKb();document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const token=adminToken();document.getElementById('main').innerHTML=`<div class="review-page"><div class="review-header review-admin-bar"><div class="review-header-left"><h2>Review Queue</h2><span class="badge b-red">admin only</span></div><div class="review-token-form"><input id="adminToken" placeholder="Admin token" value="${esc(token)}" autocomplete="off"><button class="primary" onclick="saveAdminTokenAndLoadReview()">Load Queue</button><button onclick="clearAdminToken()">Clear Token</button></div></div>${token?renderAdminInvitePanel():''}<div id="reviewList" class="grid"><div class="panel">${token?'Loading review queue…':'Review is owner-only. Enter the admin token to load the queue.'}</div></div></div>`;if(token){try{await loadReviewQueue();renderReviewList()}catch(e){document.getElementById('reviewList').innerHTML=`<div class="panel"><h3>Review unavailable</h3><p class="small">${esc(e.message||e)}</p></div>`}}}

// D-136D: admin-only invite-code creator panel — visible only inside the
