async function openReviewClaimStudy(id){lastModeBeforeStudy='review';lastInspectedReviewItemId=inspectedReviewItem?.id||null;mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(id)}
function studyFromVault(id){lastModeBeforeStudy='vault';lastInspectedReviewItemId=null;mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');selectClaim(id)}
async function saveAdminTokenAndLoadReview(){const token=document.getElementById('adminToken')?.value||'';localStorage.setItem(LS_ADMIN,token);await renderReview()}
function clearAdminToken(){localStorage.removeItem(LS_ADMIN);reviewQueue={claims:[],truths:[],review:[]};inspectedReviewItem=null;pendingRejectReviewId=null;renderReview()}
function scrollToReviewAnchor(id){if(!id)return;const el=document.querySelector('.review-inspect-panel')||document.querySelector(`[data-review-id="${id}"]`)||document.querySelector('.review-card');if(el)el.scrollIntoView({behavior:'smooth',block:'nearest'});}
async function reviewDecisionUI(targetType,targetId,decision){const _anchorId=inspectedReviewItem?.id||targetId;const item=(reviewQueue.review||[]).find(i=>i.id===targetId);const raw=item?(item.statement||item.claim||item.title||targetId):'item';const label=String(raw).slice(0,48)+(String(raw).length>48?'…':'');const msgs={public:`Approved. Item is now public.`,rejected:`Rejected. Item will not be public.`,review:`Kept in Review. Item is not yet public.`};try{await api('/api/review/decision',{method:'POST',headers:adminHeaders(),body:JSON.stringify({targetType,targetId,decision})});pendingRejectReviewId=null;pendingApproveReviewId=null;toast(msgs[decision]||`Review set to ${decision}`);loadGraphStatus().catch(()=>{});await loadReviewQueue();renderReviewList();scrollToReviewAnchor(_anchorId)}catch(e){toast(e.message||'Review action failed')}}
async function markDuplicateUI(claimId){const item=(reviewQueue.review||[]).find(i=>i.id===claimId);const raw=String(item?.claim||claimId);const label=raw.slice(0,60)+(raw.length>60?'...':'');hxModal({title:'Mark as Duplicate',body:`<p class="small" style="margin:0 0 8px">Marking <strong>${esc(label)}</strong> as a duplicate of another claim. Source is preserved — no delete, no merge.</p><label class="small" style="display:block;margin-bottom:2px">Canonical target claim ID</label><input id="dup-target-id" type="text" placeholder="clm_..." style="width:100%;box-sizing:border-box;margin-bottom:8px"><label class="small" style="display:block;margin-bottom:2px">Reason (optional)</label><input id="dup-reason" type="text" placeholder="Same claim, different wording" style="width:100%;box-sizing:border-box">`,confirmLabel:'Mark Duplicate',cancelLabel:'Cancel',onConfirm:async(close)=>{const targetId=(document.getElementById('dup-target-id')?.value||'').trim();const reason=(document.getElementById('dup-reason')?.value||'').trim();if(!targetId){toast('Target claim ID is required');return;}try{await api('/api/review/mark-duplicate',{method:'POST',headers:adminHeaders(),body:JSON.stringify({claimId,duplicateOf:targetId,reason:reason||null})});close();inspectedReviewItem=null;toast('Marked as duplicate. Claim removed from queue.');loadGraphStatus().catch(()=>{});await loadReviewQueue();renderReviewList();scrollToReviewAnchor(claimId)}catch(e){toast(e.message||'Mark duplicate failed')}}})}
async function resolveSimilarUI(claimId){const item=(reviewQueue.review||[]).find(i=>i.id===claimId);const nearDup=item?.near_duplicate_of||item?.nearDuplicateOf||'?';hxModal({title:'Dismiss Similar Advisory',body:`<p class="small" style="margin:0">Dismiss the similarity advisory linking this claim to <code>${esc(nearDup)}</code>.<br>No state change, no merge, no delete — the claim stays in Review.</p>`,confirmLabel:'Dismiss Advisory',cancelLabel:'Cancel',onConfirm:async(close)=>{try{await api('/api/review/resolve-similar',{method:'POST',headers:adminHeaders(),body:JSON.stringify({claimId})});close();toast('Similar advisory cleared.');await loadReviewQueue();renderReviewList()}catch(e){toast(e.message||'Resolve similar failed')}}})}
async function attachEvidencePrompt(evidenceId){if(!claims.length)await loadClaims(false);if(!claims.length)return toast('No claims available to attach to.');attachingEvidenceId=evidenceId;const modal=document.getElementById('attach-modal');if(!modal)return;const opts=claims.map((c,i)=>`<option value="${i}">${esc(cleanClaimLabel(c.claim))}</option>`).join('');modal.innerHTML=`<div class="attach-modal-inner"><h3>Attach to Claim</h3><p class="small">Choose a claim and how this evidence should be attached.</p><select id="attach-claim-select" style="margin-bottom:2px">${opts}</select><div class="attach-stance-row"><button class="btn-approve" onclick="doAttachEvidence('support')">Attach as Support</button><button class="btn-reject" onclick="doAttachEvidence('pressure')">Attach as Pressure</button><button class="btn-keep" onclick="closeAttachModal()">Cancel</button></div></div>`;modal.style.display='flex';}
async function doAttachEvidence(stance){const select=document.getElementById('attach-claim-select');if(!select)return;const target=claims[Number(select.value)];if(!target)return toast('Invalid claim selection');const id=attachingEvidenceId;closeAttachModal();try{await api('/api/evidence-attach',{method:'POST',body:JSON.stringify({evidenceId:id,claimId:target.id,stance})});await loadGraphStatus();toast(`Evidence attached as ${stance}`);if(mode==='vault')await renderVault()}catch(e){toast(e.message||'Could not attach evidence')}}
function closeAttachModal(){const modal=document.getElementById('attach-modal');if(modal)modal.style.display='none';attachingEvidenceId=null;}
async function submitTruth(){const statement=document.getElementById('truthStatement')?.value||'';const category=document.getElementById('truthCategory')?.value||'general';const origin=document.getElementById('truthOrigin')?.value||'unknown';const truthType=document.getElementById('truthType')?.value||'common';try{await api('/api/truths',{method:'POST',body:JSON.stringify({statement,category,origin,truthType})});await loadGraphStatus();toast('Truth submitted for Review. It will appear publicly after approval.');await renderTruths()}catch(e){toast(e.message||'Truth submission failed.')}}
function runPackSummary(){if(!selected)return'';const ev=(selected.evidence||[]).length;const pr=(selected.pressure||[]).length;const ts=(selected.tests||[]).length;const an=(selected.analyses||[]).length;let statusLabel,statusCls,statusHint;if(!lastPacket){statusLabel='No packet yet';statusCls='rp-status-idle';statusHint='Click Create Investigation Packet to build the bundle.';}else if(lastPacketClaimId&&lastPacketClaimId!==selected.id){statusLabel='Built for different claim';statusCls='rp-status-warn';statusHint='This packet was built for a different claim. Rebuild to update.';}else if(lastPacketIsFallback){statusLabel='Fallback packet';statusCls='rp-status-warn';statusHint='Generated locally — backend evidence and lineage may be incomplete.';}else{const _stale=detectPacketStaleness();if(_stale){statusLabel='Possibly stale — '+_stale;statusCls='rp-status-warn';statusHint='Rebuild the packet to capture the latest evidence and pressure.';}else{statusLabel='Packet ready · send to AI';statusCls='rp-status-ready';statusHint='Copy or download below, paste into any AI, then import the result.';}}return`<div class="rp-summary"><div class="rp-summary-row"><span class="rp-summary-count" title="Support evidence items"><b>${ev}</b> evidence</span><span class="rp-summary-count" title="Pressure / attack items"><b>${pr}</b> pressure</span><span class="rp-summary-count" title="Testable methods"><b>${ts}</b> tests</span><span class="rp-summary-count" title="Saved AI analyses"><b>${an}</b> analyses</span></div><div class="rp-summary-status"><span class="rp-status-chip ${statusCls}">${esc(statusLabel)}</span><span class="small rp-status-hint">${esc(statusHint)}</span></div></div>`;}
function renderExport(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const claimCtx=selected?`<div class="runpack-claim-ctx"><span class="pill">active claim</span><p class="runpack-claim-name">${esc(cleanClaimLabel(selected.claim))}</p><span class="badge ${cls(selected.status)}">${esc(selected.status||'unknown')}</span></div>`:'';const noClaimState=!selected?`<div class="empty-state runpack-no-claim-state"><p>No claim selected.</p><p class="small">Open a claim from the <b>Claims</b> tab → enter Study mode → click <b>Build RunPack</b>. Then return here to copy or download the packet.</p><div class="actions" style="margin-top:8px"><button class="primary" onclick="setMode('arena')">Browse Claims</button></div></div>`:'';const summary=runPackSummary();const workflowGuide=selected?'<div class="rp-workflow-guide"><span class="rp-wf-step"><span class="rp-wf-n">1</span>Create packet</span><span class="rp-wf-arr">→</span><span class="rp-wf-step"><span class="rp-wf-n">2</span>Paste into AI</span><span class="rp-wf-arr">→</span><span class="rp-wf-step"><span class="rp-wf-n">3</span>Copy AI response</span><span class="rp-wf-arr">→</span><span class="rp-wf-step"><span class="rp-wf-n">4</span>Load below</span></div>':'';const outputBlock=lastPacket?`${lastPacketIsFallback?'<p class="small runpack-fallback-warn">⚠ Fallback RunPack — generated locally from cached data. Backend evidence and lineage may be incomplete.</p>':''}<details class="rp-json-details"><summary class="rp-json-summary">Technical packet JSON</summary><p class="small rp-json-label">Copy above or paste this directly into any AI. No AI costs — paste into any AI you already use.</p><pre class="output runpack-export-output">${esc(lastPacket)}</pre></details>`:(selected?'<p class="small runpack-ready-hint">Click <b>Create Investigation Packet</b> above to build the bundle, then copy or download it to paste into your AI.</p>':'');document.getElementById('main').innerHTML=`<div class="panel"><h2>Investigation Packet</h2><p class="small">An investigation packet is a portable, AI-agnostic bundle containing a claim, its evidence, pressure, tests, and analyses. Paste it into any AI for pressure-testing — no owner API credits used.</p><p class="small review-first-note">Creating a packet does not publish anything — visibility still depends on admin Review approval.</p>${claimCtx}${summary}${noClaimState}${workflowGuide}<div class="runpack-actions"><button class="primary" onclick="generateRunPack()">${lastPacket&&lastPacketClaimId===selected?.id?'Recreate Packet':'Create Investigation Packet'}</button><button onclick="copyAIP()" title="Copy the packet to clipboard (generates first if needed)">Copy Packet</button><button onclick="downloadRunPack()" title="Download the packet as a JSON file">Download Packet</button></div><details class="runpack-visible-data-toggle"><summary>Download all visible data</summary><p class="small">Exports everything currently visible in your session — claims, evidence, truths, belief snapshots, graph status. Not the same as an investigation packet.</p><div class="actions"><button onclick="downloadJSON()">Download all visible data JSON</button></div></details>${outputBlock}${selected?`<details class="rp-return-section"><summary class="rp-return-head">Load AI Analysis Return</summary><div class="rp-return-body"><p class="small">Paste the JSON result from your AI here to save it as a structured analysis for this claim.</p><textarea id="analysisPaste" placeholder="Paste the AI's JSON response here"></textarea><div class="actions"><button class="primary" onclick="saveAnalysisResult()">Save Analysis</button></div></div></details>`:''}</div>`}
async function selectClaim(id){try{const data=await api('/api/claims/'+id);selected=data.claim;selected.claim=cleanClaimLabel(selected.claim);selected.evidence=data.evidence||[];selected.pressure=data.pressure||[];selected.tests=data.tests||data.home_tests||[];selected.analyses=data.analyses||[];selected.lineage=data.lineage||null;if(lastModeBeforeStudy==='arena'){const _ms=document.getElementById('main');if(_ms)lastArenaScrollTop=_ms.scrollTop;}renderStudy();toast('Study loaded')}catch(e){const fallback=claims.find(c=>c.id===id)||selected;if(fallback){selected=fallback;selected.analyses=selected.analyses||[];selected.lineage=selected.lineage||null;renderStudy()}toast(e.message||'Could not load claim')}}
function reviewStatusBadge(c,withNote=false,truthCtx=false){const rs=c.review_state||c.reviewState||c.visibility||'';const reports=c.report_count||c.reportCount||0;let label='',clr='';if(reports>0){label='Reported';clr='b-red';}else if(rs==='public'||rs==='approved'||rs==='live'){label=truthCtx?'visible':'Public';clr=truthCtx?'b-muted truth-visible-badge':'b-green';}else if(rs==='rejected'){label='Rejected';clr='b-red';}else if(rs==='archived'){label='Archived';clr='b-yellow';}else if(rs==='review'||rs==='pending'||rs==='queued'){label='Pending Review';clr='b-yellow';}if(!label)return'';if(!withNote)return`<div class="review-badge-block"><span class="badge ${clr}">${label}</span></div>`;const note=rs==='rejected'?'<p class="small study-review-note">This claim is kept out of public view.</p>':label==='Pending Review'?'<p class="small study-review-note">This claim is not public until approved.</p>':'';return`<div class="study-review-state"><span class="badge ${clr}">${label}</span>${note}</div>`}
function studyReviewBadge(c){return reviewStatusBadge(c,true)}
function renderStudy(){if(!selected)return;document.body.classList.add('study-mode');document.getElementById('side-tools').style.display='block';const studyMeta=[selected.category,selected.type,selected.handle?'by '+selected.handle:''].filter(Boolean).map(esc).join(' · ');document.getElementById('main').innerHTML=`<div class="study"><div class="study-header"><div class="study-nav"><button onclick="backToArena()">${lastModeBeforeStudy==='review'?'← Back to Review':lastModeBeforeStudy==='vault'?'← Back to Vault':lastModeBeforeStudy==='truths'?'← Back to Truths':lastModeBeforeStudy==='me'?'← Back to My HumanX':'← Back'}</button><span class="badge ${cls(selected.status)}">${esc(selected.status||'unknown')}</span></div><h2>${esc(cleanClaimLabel(selected.claim))}</h2>${studyReviewBadge(selected)}${studyMeta?`<p class="study-meta small">${studyMeta}</p>`:''}<div class="meters wide">${meter('Evidence',selected.evidenceScore)}${meter('Testability',selected.testability)}${meter('Survivability',selected.survivability)}</div><p class="study-verdict-qualifier small">Verdict is a pressure-test label, not an automatic truth ruling. Scores reflect the current submitted packet, not absolute certainty.</p><div class="study-vote-row"><div class="study-votes"><span class="study-vote-label">Vote</span><button class="vote yes" onclick="voteClaim('believe')">▲ Believe</button><button class="vote no" onclick="voteClaim('reject')">▼ Reject</button><button class="vote unsure" onclick="voteClaim('unsure')">~ Unsure</button></div><div class="study-actions"><button class="primary" onclick="generateRunPack()">Build RunPack</button></div></div></div>${sectionArgumentFlow()}${sectionLineage()}<div class="inv-board-head"><span>Investigation Board</span></div><div class="study-grid"><section class="panel evidence-panel">${sectionEvidence()}</section><section class="panel pressure-panel">${sectionPressure()}</section><section class="panel tests-panel">${sectionTests()}</section><section class="panel analysis-panel">${sectionAnalyses()}</section></div></div>`;renderCaseMini();patchEvidencePanel();patchRunPackPanel()}
function renderCaseMini(){const l=selected?.lineage||{};const ev=(l.evidenceLinks||[]).length;const pr=l.pressureCount||0;const ts=l.testCount||0;const an=l.analysisCount||0;const rs=selected.review_state||selected.reviewState||'';const rsLabel=rs==='public'?'Public':rs==='rejected'?'Rejected':rs==='review'||rs==='pending'||rs==='queued'?'Pending Review':'';const rsCls=rs==='public'?'b-green':rs==='rejected'?'b-red':'b-yellow';document.getElementById('casefile').innerHTML=`<p class="casefile-claim-name">${esc(cleanClaimLabel(selected.claim))}</p>${rsLabel?`<div class="casefile-badge-row"><span class="badge ${rsCls}">${rsLabel}</span></div>`:''}<div class="casefile-counts"><span title="Support evidence">${ev} evidence</span><span title="Pressure attacks">${pr} pressure</span><span title="Tests">${ts} tests</span><span title="Saved analysis">${an} analysis</span></div>`}
function evidenceQualityLabel(q){const k=String(q||'').trim().toLowerCase();const map={repeatable:'repeatable',documented:'documented',media:'media',testimony:'testimony',vibes:'weak argument'};return map[k]||k;}
function evidenceQualityClass(q){const k=String(q||'').trim().toLowerCase();if(k==='repeatable'||k==='documented')return 'ev-q-strong';if(k==='media'||k==='testimony')return 'ev-q-mid';if(k==='vibes')return 'ev-q-weak';return 'ev-q-neutral';}
function evidenceMeta(e){const reused=e.link_type==='reused';const stance=e.linked_stance||e.stance||'support';const quality=e.quality?evidenceQualityLabel(e.quality):'';const parts=[reused?'reused':null,quality||null,stance].filter(Boolean);return parts.map(esc).join(' · ')}
function evidenceItem(e){const a=parseAnalysis(e.body||e.note);if(a)return`<div class="row analysis-card"><div class="inv-item-head"><b class="inv-item-title">${esc(e.title)}</b><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><span class="pill">legacy</span></div><div class="meters">${meter('Evidence',a.evidence_score||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||'Structured AIP/AI analysis stored in old evidence field.')}</p><details><summary>Support / pressure / missing tests</summary><h4>Support</h4>${listBits(a.strongest_support)}<h4>Pressure</h4>${listBits(a.strongest_pressure)}<h4>Missing tests</h4>${listBits(a.missing_tests)}</details></div>`;const reused=e.link_type==='reused';return`<div class="row${reused?' ev-row-reused':''}"><div class="inv-item-head"><b class="inv-item-title">${esc(e.title)}</b><span class="pill ${evidenceQualityClass(e.quality)}">${evidenceMeta(e)}</span></div>${evidenceBodyHtml(e.body||e.note,300)}${e.link_note?`<p class="small"><b>Reuse note:</b> ${esc(e.link_note)}</p>`:''}${sourceLink(e.source_url||e.sourceUrl)}</div>`}
function analysisItem(a){const raw=a.raw||a;const verdict=a.verdict||raw.verdict||'analysis';const summary=a.plainLanguageSummary||raw.plain_language_summary||'Stored analysis result.';const src=a.source||raw.source||'runpack-user';return`<div class="analysis-result-card"><div class="inv-item-head"><span class="badge ${cls(verdict)}">${esc(verdict)}</span><span class="pill">${esc(src)}</span></div><div class="meters">${meter('Evidence',a.evidenceScore||raw.evidence_score||0)}${meter('Test',a.testability||raw.testability||0)}${meter('Survive',a.survivability||raw.survivability||0)}</div><p class="small">${esc(summary)}</p><details class="analysis-details"><summary>Support · Pressure · Missing tests</summary><div class="analysis-detail-grid"><div><h4>Support</h4>${listBits(a.strongestSupport||raw.strongest_support)}</div><div><h4>Pressure</h4>${listBits(a.strongestPressure||raw.strongest_pressure)}</div><div><h4>Missing tests</h4>${listBits(a.missingTests||raw.missing_tests)}</div></div></details></div>`}
function sectionLineage(){const l=selected?.lineage||{};const truths=l.truths||[];const evidenceLinks=l.evidenceLinks||[];return`<section class="panel lineage-panel"><div class="section-head"><h3>Lineage</h3><span class="badge b-blue">upstream origin</span></div><div class="graph-status"><span><b>${esc((l.beliefs||[]).length)}</b><small>Beliefs</small></span><span><b>${esc(truths.length)}</b><small>Truths</small></span><span><b>1</b><small>Claim</small></span><span><b>${esc(evidenceLinks.length)}</b><small>Evidence</small></span><span><b>${esc(l.pressureCount||0)}</b><small>Pressure</small></span><span><b>${esc(l.testCount||0)}</b><small>Tests</small></span><span><b>${esc(l.analysisCount||0)}</b><small>Analysis</small></span></div>${truths.length?`<div class="row"><span class="pill">upstream truth</span>${truths.slice(0,3).map(t=>`<p class="small"><b>${esc(cleanClaimLabel(t.statement||'Truth'))}</b><br>${esc(t.bridge_note||t.origin||'Linked truth')}</p>`).join('')}</div>`:'<p class="small">No upstream truth linked yet. This claim may have been submitted directly or promoted from a belief without a formal truth bridge.</p>'}</section>`}
function firstEvidence(){return(selected.evidence||[]).find(e=>!parseAnalysis(e.body||e.note))}
function firstPressure(){return(selected.pressure||[])[0]}
function firstTest(){return(selected.tests||[])[0]}
function firstAnalysis(){return(selected.analyses||[])[0]}
function sectionArgumentFlow(){const e=firstEvidence(),p=firstPressure(),t=firstTest(),a=firstAnalysis();const raw=a?.raw||a||{};return`<section class="panel flow-panel"><div class="section-head"><h3>Claim Flow</h3><span class="badge b-green">read this first</span></div><div class="flow-steps"><div class="row"><span class="pill">1 · Why people think it is true</span><p class="small">${e?`<b>${esc(e.title||'Evidence')}</b><br>${esc(shortText(e.body||e.note,260))}`:'No support evidence attached yet — add one from the side panel.'}</p></div><div class="row"><span class="pill">2 · What attacks it</span><p class="small">${p?`<b>${esc(p.title||'Pressure')}</b><br>${esc(shortText(p.body||p.note,260))}`:'No pressure attached yet — add an objection from the side panel.'}</p></div><div class="row"><span class="pill">3 · How to test it</span><p class="small">${t?`<b>${esc(t.title||'Test')}</b><br>${esc(shortText(t.instructions,260))}`:'No test added yet — add one in the Tests section below.'}</p></div><div class="row"><span class="pill">4 · What analysis says</span><p class="small">${a?`<b>${esc(a.verdict||raw.verdict||'Analysis')}</b><br>${esc(shortText(a.plainLanguageSummary||raw.plain_language_summary||'Stored analysis result.',260))}`:'No analysis saved yet — generate a RunPack and paste the result below.'}</p></div></div></section>`}
function reusedItemCompact(e){return`<div class="reused-item-compact"><span class="inv-item-title">${esc(e.title)}</span><span class="pill ${evidenceQualityClass(e.quality)}">${evidenceMeta(e)}</span>${e.link_note?`<span class="reused-item-note">${esc(e.link_note)}</span>`:''} ${sourceLink(e.source_url||e.sourceUrl)}</div>`}
function reusedEvidenceHtml(reused){const subHead=`<div class="study-sub-head study-sub-reused">Reused from vault<span class="badge">${reused.length}</span></div>`;if(reused.length<=3)return`<div class="reused-block">${subHead}${reused.map(reusedItemCompact).join('')}</div>`;const groups=new Map();for(const e of reused){const key=e.claim_id||'unknown';if(!groups.has(key)){const src=(claims||[]).find(c=>c.id===key);groups.set(key,{claimId:key,claimText:src?.claim||null,items:[]});}groups.get(key).items.push(e);}const sorted=[...groups.values()].sort((a,b)=>b.items.length-a.items.length);const groupsHtml=sorted.map(g=>{const label=g.claimText?cleanClaimLabel(g.claimText):`claim ${g.claimId.slice(-6)}`;return`<details class="reused-source-group"><summary class="reused-source-head"><span class="reused-source-label">${esc(label)}</span><span class="badge">${g.items.length} item${g.items.length===1?'':'s'}</span></summary><div class="reused-source-items">${g.items.map(reusedItemCompact).join('')}</div></details>`;}).join('');if(reused.length>=4)return`<details class="reused-collapse-outer"><summary class="reused-collapse-head"><span class="study-sub-reused">Reused from vault</span><span class="badge">${reused.length} items</span><span class="reused-collapse-hint">· ${sorted.length} source claim${sorted.length===1?'':'s'} · click to expand</span></summary><div class="reused-collapse-body">${groupsHtml}</div></details>`;return subHead+groupsHtml;}
function sectionEvidence(){const ev=selected.evidence||[];const head=`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Support Evidence</h3><span class="badge b-blue">${ev.length} item${ev.length===1?'':'s'}</span></div><p class="inv-sec-purpose">What currently supports this claim.</p></div>`;if(!ev.length)return head+'<div class="empty-state"><p>No supporting evidence yet.</p><p class="small">Use the side panel to add a source, document, or reuse an existing vault item.</p></div>';const analyses=ev.filter(e=>parseAnalysis(e.body||e.note));const direct=ev.filter(e=>!parseAnalysis(e.body||e.note)&&e.link_type!=='reused');const reused=ev.filter(e=>!parseAnalysis(e.body||e.note)&&e.link_type==='reused');const hasGroups=direct.length>0&&reused.length>0;if(!hasGroups){if(reused.length>0)return head+reusedEvidenceHtml(reused);return head+ev.map(evidenceItem).join('');}return head+analyses.map(evidenceItem).join('')+(direct.length?`<div class="study-sub-head">Direct evidence<span class="badge b-blue">${direct.length}</span></div>${direct.map(evidenceItem).join('')}`:'')+( reused.length?reusedEvidenceHtml(reused):'');}
function pressureItemHtml(p){const a=parseAnalysis(p.body||p.note);return a?`<div class="row analysis-card"><div class="inv-item-head"><b class="inv-item-title">${esc(p.title)}</b><span class="badge ${cls(a.verdict||'analysis')}">${esc(a.verdict||'analysis')}</span><span class="pill">legacy</span></div><p class="small">${esc(a.plain_language_summary||'Structured analysis pressure result.')}</p>${listBits(a.strongest_pressure)}</div>`:`<div class="row"><div class="inv-item-head"><b class="inv-item-title">${esc(p.title)}</b><span class="pill">severity ${esc(p.severity||1)}</span></div>${evidenceBodyHtml(p.body||p.note,300)}</div>`;}
function sectionPressure(){const pr=selected.pressure||[];const head=`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Pressure / Attacks</h3><span class="badge b-yellow">${pr.length} item${pr.length===1?'':'s'}</span></div><p class="inv-sec-purpose">What challenges, contradicts, or weakens it.</p></div>`;if(!pr.length)return head+'<div class="empty-state"><p>No pressure or attacks yet.</p><p class="small">Use the side panel to add an objection, contradiction, or counter-evidence.</p></div>';const analyses=pr.filter(p=>parseAnalysis(p.body||p.note));const plain=pr.filter(p=>!parseAnalysis(p.body||p.note));const high=plain.filter(p=>(p.severity||1)>=3);const other=plain.filter(p=>(p.severity||1)<3);const hasGroups=high.length>0&&other.length>0;if(!hasGroups)return head+pr.map(pressureItemHtml).join('');return head+analyses.map(pressureItemHtml).join('')+(high.length?`<div class="study-sub-head study-sub-high">Significant pressure<span class="badge b-red">${high.length}</span></div>${high.map(pressureItemHtml).join('')}`:'')+( other.length?`<div class="study-sub-head">Other pressure<span class="badge">${other.length}</span></div>${other.map(pressureItemHtml).join('')}`:'');}
function sectionTests(){const ts=selected.tests||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Tests</h3><span class="badge b-green">${ts.length} test${ts.length===1?'':'s'}</span></div><p class="inv-sec-purpose">Ways this claim could be checked or falsified.</p></div><div class="test-add-form"><input id="testTitle" placeholder="Test title"><textarea id="testInstructions" placeholder="Instructions: what to do, what to record, how to repeat it"></textarea><div class="test-form-row"><select id="testSafety"><option value="low">low safety risk</option><option value="medium">medium safety risk</option><option value="high">high safety risk</option></select><select id="testDifficulty"><option value="easy">easy</option><option value="medium">medium</option><option value="hard">hard</option></select></div><button class="primary" onclick="addHomeTestUI()">Add Test</button></div>${ts.map(t=>`<div class="test-item"><div class="inv-item-head"><b class="inv-item-title">${esc(t.title)}</b><span class="pill">${esc(t.difficulty||'test')} · ${esc(t.safety_level||t.safetyLevel||'normal')}</span></div><p class="small">${esc(t.instructions)}</p></div>`).join('')||'<div class="empty-state"><p>No tests yet.</p><p class="small">A test describes a real-world way this claim could be checked or falsified. Use the form above to add one.</p></div>'}`}
function sectionAnalyses(){const an=selected.analyses||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Analysis</h3><span class="badge b-blue">${an.length} result${an.length===1?'':'s'}</span></div><p class="inv-sec-purpose">Saved RunPack or AI analysis results.</p></div><div class="analysis-save-form"><p class="small">Click <b>Build RunPack</b> in the claim header → paste into any AI → paste the JSON result here to save it.</p><textarea id="analysisPaste" placeholder="Paste RunPack output JSON here"></textarea><div class="actions"><button class="primary" onclick="saveAnalysisResult()">Save Analysis</button></div></div>${an.map(analysisItem).join('')||'<div class="empty-state"><p>No analysis saved yet.</p><p class="small">Build a RunPack above → paste it into any AI → paste the JSON result back here to save it against this claim.</p></div>'}`}
function backToArena(){document.body.classList.remove('study-mode');selected=null;const _origin=lastModeBeforeStudy;if(_origin==='review'){const _savedId=lastInspectedReviewItemId;lastInspectedReviewItemId=null;if(_savedId){const _found=(reviewQueue.review||[]).find(i=>i.id===_savedId);if(_found)inspectedReviewItem=_found;}setMode('review');}else if(_origin==='vault'){setMode('vault');}else if(_origin==='truths'){setMode('truths');}else if(_origin==='me'){setMode('me');}else{setMode('arena');const _mr=document.getElementById('main');if(_mr)_mr.scrollTop=lastArenaScrollTop;}}
async function voteClaim(vote){if(!selected)return toast('Select a claim first');try{const data=await api('/api/claim-vote',{method:'POST',body:JSON.stringify({claimId:selected.id,vote})});selected=data.claim||selected;toast('Vote recorded');await loadGraphStatus();await loadClaims(false);await selectClaim(selected.id)}catch(e){toast(e.message||'Vote route not wired yet')}}
async function saveClaim(){const body={claim:document.getElementById('cClaim').value,category:document.getElementById('cCategory').value,type:document.getElementById('cType').value,initialEvidence:document.getElementById('cEvidence').value};try{const data=await api('/api/claims',{method:'POST',body:JSON.stringify(body)});selected=data.claim;await loadGraphStatus();await loadClaims(false);if(data.existing){toast('This claim already exists.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-blue">already exists</span><h2>Claim already exists</h2><p class="small">A claim with the same meaning is already in the system.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study existing claim</button><button onclick="setMode('submit')">Submit a different claim</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`}else{if(data.nearDuplicate){toast('Submitted for Review. A similar claim may already exist.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-yellow">in review</span> <span class="badge b-yellow">similar exists</span><h2>Claim submitted for Review</h2><p class="small">Your claim is now in the moderation queue. A similar claim may already exist — a moderator will review both.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p>${data.similarClaim?`<p class="small">Similar claim: <b>${esc(cleanClaimLabel(data.similarClaim.claim))}</b></p>`:''}<div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study this claim</button>${data.similarClaim?`<button onclick="selectClaim('${esc(data.similarClaim.id)}')">Study similar claim</button>`:''}<button onclick="setMode('submit')">Submit another</button></div></div>`}else{toast('Claim submitted for Review. It will appear publicly after approval.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-yellow">in review</span><h2>Claim submitted for Review</h2><p class="small">Your claim is now in the moderation queue and is not yet public. It will appear publicly after an admin approves it.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study this claim</button><button onclick="setMode('submit')">Submit another</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`}}}catch(e){const _em=e.message||'';toast(_em==='RATE_LIMITED'?'Too many submissions. Try again in about an hour.':_em==='CLAIM_TOO_SHORT'?'Claim is too short. Add a little more detail before submitting.':_em||'Claim submission failed.')}}
async function addCaseItem(){if(!selected)return toast('Select a claim first');const kind=document.getElementById('eKind').value;const payload={claimId:selected.id,title:document.getElementById('eTitle').value,quality:document.getElementById('eQuality').value,body:document.getElementById('eNote').value,sourceUrl:document.getElementById('eSource')?.value||''};try{const data=await api(kind==='evidence'?'/api/evidence':'/api/pressure',{method:'POST',body:JSON.stringify(payload)});selected=data.claim||selected;await loadGraphStatus();await selectClaim(selected.id);document.getElementById('eTitle').value='';document.getElementById('eNote').value='';if(document.getElementById('eSource'))document.getElementById('eSource').value='';toast(kind==='evidence'?'Evidence attached to selected claim.':'Pressure point submitted for review.')}catch(e){toast(e.message||'Evidence attach failed.')}}
async function addHomeTestUI(){if(!selected)return toast('Select a claim first');const title=(document.getElementById('testTitle')?.value||'').trim();const instructions=(document.getElementById('testInstructions')?.value||'').trim();if(!title)return toast('Enter a test title before adding.');if(instructions.length<8)return toast('Instructions need at least 8 characters — describe what to do and record.');const body={claimId:selected.id,title,instructions,safetyLevel:document.getElementById('testSafety')?.value||'low',difficulty:document.getElementById('testDifficulty')?.value||'easy'};try{await api('/api/tests',{method:'POST',body:JSON.stringify(body)});toast('Test added');await selectClaim(selected.id)}catch(e){toast(e.message||'Could not add test')}}
function reportSelected(){if(!selected)return toast('Select a claim first');const claimLabel=esc(cleanClaimLabel(selected.claim));hxModal({title:'Report Claim',body:`<p class="small" style="margin:0 0 4px;color:var(--text)">${claimLabel}</p><textarea id="hx-report-reason" placeholder="Why report this claim?" rows="3" style="width:100%;margin-top:6px;resize:vertical"></textarea>`,confirmLabel:'Send Report',onConfirm:close=>{const reason=(document.getElementById('hx-report-reason')?.value||'').trim();if(!reason)return;close();api('/api/report',{method:'POST',body:JSON.stringify({targetType:'claim',targetId:selected.id,reason})}).then(()=>loadGraphStatus()).then(()=>toast('Report sent')).catch(e=>toast(e.message||'Report failed'));}});}
async function convertTruth(truthId){try{const _ctOpts={method:'POST',body:JSON.stringify({truthId})};if(adminToken())_ctOpts.headers=adminHeaders();const data=await api('/api/truth-to-claim',_ctOpts);let msg;if(!data.existing){msg='Claim created from truth and sent to Review.';}else if(data.bridge?.claimId){msg='Existing public claim opened in Study.';}else{const st=data.bridge?.claimState;if(st==='rejected')msg='This truth was already pressure-tested and rejected.';else if(st==='review')msg='Claim already in Review queue.';else if(st==='archived')msg='Existing pressure-test was archived.';else if(st==='duplicate')msg='Existing pressure-test was marked duplicate.';else msg='Existing pressure-test is not public.';}toast(msg);mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await loadGraphStatus();await loadClaims(false);if(data.bridge?.claimId)await selectClaim(data.bridge.claimId)}catch(e){toast(e.message||'Truth-to-claim conversion failed.')}}
function generatePacketId(claimId){const ts=Date.now().toString(36);const short=(claimId||'').slice(-6);return'rp_'+short+'_'+ts}
function simpleClaimHash(claim){const s=[claim.id||'',claim.updated_at||'',(claim.evidence||[]).length,(claim.pressure||[]).length,(claim.tests||[]).length].join('|');let h=0;for(let i=0;i<s.length;i++){h=(Math.imul(31,h)+s.charCodeAt(i))|0;}return(h>>>0).toString(16)}
function buildProvenanceMeta(claim){return{packet_id:generatePacketId(claim.id),runpack_version:'1.2',generated_at:new Date().toISOString(),source_claim_id:claim.id,source_snapshot_hash:simpleClaimHash(claim),evidence_count:(claim.evidence||[]).length,pressure_count:(claim.pressure||[]).length,test_count:(claim.tests||[]).length,humanx_app_version:'v10',is_fallback:false}}
function detectPacketStaleness(){if(!lastPacket||!selected)return null;let meta;try{meta=JSON.parse(lastPacket)}catch(e){return null}if(!meta.packet_id)return null;const w=[];if(meta.evidence_count!=null&&meta.evidence_count!==(selected.evidence||[]).length)w.push('evidence count changed');if(meta.pressure_count!=null&&meta.pressure_count!==(selected.pressure||[]).length)w.push('pressure count changed');if(meta.test_count!=null&&meta.test_count!==(selected.tests||[]).length)w.push('test count changed');if(meta.generated_at){const ageMs=Date.now()-new Date(meta.generated_at).getTime();if(ageMs>3600000)w.push('packet is '+Math.floor(ageMs/3600000)+'h old');}return w.length?w.join(' · '):null}
async function generateRunPack(){if(!selected)return toast('Open a claim first');const provenance=buildProvenanceMeta(selected);try{const data=await api('/api/runpack',{method:'POST',body:JSON.stringify({claimId:selected.id})});const _wp=!!(data.packet&&data.packet.packet_id);const _mp=_wp?{humanx_app_version:'v10'}:provenance;lastPacket=JSON.stringify({...data.packet,..._mp},null,2);lastPacketIsFallback=false}catch(e){lastPacket=JSON.stringify({...provenance,is_fallback:true,legacy_aip_version:'1.1',aip_version:'1.1',packet_type:'runpack_task',app:'HumanX',mode:'claim-pressure-analysis',no_owner_api_used:true,payload:selected},null,2);lastPacketIsFallback=true}lastPacketClaimId=selected.id;lastPacketMeta=provenance;const statusEl=document.getElementById('aip-status');if(statusEl){statusEl.textContent='RunPack ready — copy it here or open the RunPack tab for full JSON and download.';statusEl.classList.add('runpack-side-status-ready');}if(mode==='export')renderExport();toast('RunPack ready — copy it into your AI')}
function patchEvidencePanel(){const tools=document.getElementById('side-tools');if(!tools)return;const kindSelect=document.getElementById('eKind');if(kindSelect&&!document.getElementById('evidence-kind-hint')){const hint=document.createElement('p');hint.id='evidence-kind-hint';hint.className='small evidence-kind-hint';hint.innerHTML='<b>Support</b> backs the claim. <b>Attack</b> challenges or contradicts it.';kindSelect.after(hint)}const attachBtn=tools.querySelector('button[onclick="addCaseItem()"]');if(attachBtn&&!document.getElementById('evidence-attach-note')){const note=document.createElement('p');note.id='evidence-attach-note';note.className='small review-first-note';note.style.marginTop='3px';note.textContent='Saved to selected claim. Visibility follows Review state.';attachBtn.after(note)}}
function patchRunPackPanel(){const status=document.getElementById('aip-status');if(!status)return;status.className='runpack-side-status small';if(lastPacket&&!lastPacketIsFallback){status.textContent='RunPack ready — copy it here or open the RunPack tab for full JSON and download.';status.classList.add('runpack-side-status-ready');}else if(lastPacketIsFallback){status.textContent='⚠ Fallback RunPack — backend unavailable. Copy with caution.';status.classList.add('runpack-side-status-fallback');}else{status.textContent='Build an Investigation Packet, then copy it into any AI for pressure-testing.';}}
async function generateAIP(){return generateRunPack()}
async function copyAIP(){if(!lastPacket)await generateRunPack();navigator.clipboard.writeText(lastPacket);toast('RunPack copied')}
async function saveAnalysisResult(){if(!selected)return toast('Open a claim first');const box=document.getElementById('analysisPaste');const text=box?.value||'';let parsed;try{parsed=JSON.parse(text)}catch(e){return toast('Paste valid JSON first')}if(parsed.packet_id&&lastPacket){try{const _pm=JSON.parse(lastPacket);if(_pm.packet_id&&_pm.packet_id!==parsed.packet_id)toast('Advisory: AI return packet_id does not match current packet — analysis may be from an earlier build.');}catch(e){}}const result=parsed.output||parsed.result||parsed.analysis||parsed;try{await api('/api/analysis',{method:'POST',body:JSON.stringify({claimId:selected.id,source:'runpack-user',raw:result})});if(box)box.value='';toast('Analysis saved');await selectClaim(selected.id)}catch(e){toast(e.message||'Could not save analysis')}}
function downloadJSON(){const blob=new Blob([JSON.stringify({user,claims,evidenceVault,truths,beliefSnapshots,graphStatus},null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='humanx-visible-data.json';a.click();URL.revokeObjectURL(a.href)}
function downloadRunPack(){if(!lastPacket)return toast('Build a RunPack first — click Build RunPack above.');const name='runpack-'+(selected?.id||'claim').slice(0,24)+'.json';const blob=new Blob([lastPacket],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();URL.revokeObjectURL(a.href);toast('RunPack downloaded')}
function renderError(e){document.getElementById('main').innerHTML=`<div class="panel"><h2>HumanX backend notice</h2><p class="small">${esc(e.message||e)}</p><div class="actions" style="margin-top:10px"><button class="primary" onclick="setMode('home')">← Back to Home</button></div></div>`}
